import type { ExamQuestion } from "./types";

export const rnPathoCardioNeuroQuestions: ExamQuestion[] = [
  // ===== MYOCARDIAL INFARCTION (Questions 1-40) =====
  { q: "A patient presents with substernal chest pressure radiating to the left arm for 45 minutes. ECG shows ST elevation in leads V1-V4. What is the priority intervention?", o: ["Administer sublingual nitroglycerin ×3", "Activate cardiac catheterization lab for emergent PCI", "Obtain serial troponin levels before intervention", "Administer oral aspirin and observe"], a: 1, r: "Anterior STEMI (V1-V4) requires emergent PCI within 90 minutes. Delaying for serial troponins or NTG trials wastes critical time. Aspirin should be given but does not replace emergent reperfusion.", s: "Cardiovascular" },
  { q: "Which ECG leads indicate an inferior wall MI?", o: ["V1-V4", "I, aVL", "II, III, aVF", "V5-V6"], a: 2, r: "Leads II, III, aVF correspond to the inferior wall of the heart, typically supplied by the right coronary artery. Always obtain V4R to assess for right ventricular involvement in inferior MI.", s: "Cardiovascular" },
  { q: "A nurse administers aspirin 325 mg to a patient with suspected MI. The patient asks why they must chew it. What is the best response?", o: ["Chewing prevents stomach upset", "Chewing provides faster absorption through the oral mucosa for rapid antiplatelet effect", "Swallowing whole is equally effective", "Chewing improves the taste"], a: 1, r: "Buccal absorption from chewing achieves antiplatelet effect in 15-20 minutes versus 60+ minutes if swallowed whole. Speed is critical in acute MI.", s: "Cardiovascular" },
  { q: "Post-PCI, the patient develops a large hematoma at the femoral puncture site with dropping hemoglobin. What is the nurse's first action?", o: ["Apply firm manual pressure to the site and notify the provider", "Elevate the leg and apply ice", "Document the finding and reassess in 1 hour", "Administer vitamin K"], a: 0, r: "Expanding hematoma with hemoglobin drop indicates active bleeding. Direct manual pressure is the immediate intervention. Notify the provider for possible surgical consult or vascular closure device evaluation.", s: "Cardiovascular" },
  { q: "A patient with inferior STEMI develops hypotension (BP 72/48) and clear lung fields. JVD is present. Which intervention should the nurse anticipate?", o: ["IV furosemide", "IV normal saline bolus", "IV nitroglycerin", "Emergent intubation"], a: 1, r: "Inferior MI + hypotension + clear lungs + JVD = right ventricular infarction. The RV is preload-dependent. IV fluid resuscitation is indicated. Avoid NTG and diuretics as both reduce preload.", s: "Cardiovascular" },
  { q: "Troponin I is 0.08 ng/mL (normal <0.04) at presentation and rises to 2.4 ng/mL 6 hours later. What does this pattern indicate?", o: ["Chronic kidney disease elevation", "Acute myocardial infarction with dynamic rise-and-fall pattern", "Laboratory error", "Normal physiological variation"], a: 1, r: "A dynamic rise-and-fall pattern in troponin with at least one value above the 99th percentile, plus clinical ischemia evidence, meets the universal definition of acute MI.", s: "Cardiovascular" },
  { q: "Which medication is contraindicated in a patient who took sildenafil 12 hours ago and now has chest pain?", o: ["Aspirin", "Morphine", "Nitroglycerin", "Heparin"], a: 2, r: "NTG + PDE5 inhibitors (sildenafil) cause severe hypotension through synergistic cGMP-mediated vasodilation. Contraindicated within 24 hours of sildenafil and 48 hours of tadalafil.", s: "Cardiovascular" },
  { q: "A patient 3 days post-MI develops a new harsh holosystolic murmur and acute hemodynamic deterioration. What complication is suspected?", o: ["Dressler syndrome", "Ventricular septal rupture or papillary muscle rupture", "Pulmonary embolism", "Cardiac tamponade"], a: 1, r: "New systolic murmur day 3-5 post-MI with hemodynamic collapse suggests mechanical complication: VSD (left sternal border murmur with thrill) or papillary muscle rupture (mitral regurgitation murmur at apex). Both require emergent surgery.", s: "Cardiovascular" },
  { q: "When should a beta-blocker be initiated after acute MI?", o: ["Immediately during the acute event regardless of hemodynamics", "Within 24 hours if no contraindications", "After 1 week", "Only if heart failure develops"], a: 1, r: "Beta-blockers reduce myocardial O2 demand, recurrent ischemia, arrhythmias, and mortality. Start within 24 hours if no contraindications (cardiogenic shock, severe bradycardia, decompensated HF).", s: "Cardiovascular" },
  { q: "What is the antidote for heparin-induced bleeding?", o: ["Vitamin K", "Protamine sulfate", "Aminocaproic acid", "Fresh frozen plasma"], a: 1, r: "Protamine sulfate binds heparin, forming an inactive complex. Dose: 1 mg per 100 units heparin given in the last 2-3 hours. Vitamin K reverses warfarin, not heparin.", s: "Cardiovascular" },
  { q: "Select ALL nursing assessments appropriate for a patient 2 hours post-tPA for STEMI.", o: ["Neurological assessment for signs of intracranial hemorrhage", "Monitor for reperfusion arrhythmias on telemetry", "Check all puncture sites for bleeding", "Encourage ambulation to prevent DVT", "Strict BP monitoring"], t: "sata", ca: [0, 1, 2, 4], r: "Post-tPA requires monitoring for hemorrhage (neuro checks, puncture site bleeding), reperfusion arrhythmias, and strict BP control. Ambulation is inappropriate during the acute phase.", s: "Cardiovascular" },
  { q: "Select ALL findings that indicate successful reperfusion after PCI for STEMI.", o: ["Resolution of chest pain", "ST segment normalization", "Accelerated idioventricular rhythm", "Worsening hypotension", "Peak and decline of troponin"], t: "sata", ca: [0, 1, 2, 4], r: "Signs of reperfusion: pain relief, ST resolution, reperfusion arrhythmias (AIVR), and troponin washout (rapid peak then decline). Worsening hypotension suggests a complication.", s: "Cardiovascular" },
  { q: "Select ALL contraindications for IV alteplase (tPA) in acute MI.", o: ["Active internal bleeding", "Prior intracranial hemorrhage", "Surgery within 3 weeks", "Blood pressure 155/92 mmHg", "Chest pain >20 minutes"], t: "sata", ca: [0, 1, 2], r: "tPA contraindications: active bleeding, prior ICH, recent surgery/trauma. BP 155/92 is not a contraindication (threshold is >185/110 for stroke; different for MI). Prolonged chest pain is an indication, not contraindication.", s: "Cardiovascular" },
  { q: "Select ALL medications in the MONA mnemonic for acute MI.", o: ["Morphine", "Oxygen (if SpO2 <94%)", "Nitroglycerin", "Aspirin", "Amiodarone"], t: "sata", ca: [0, 1, 2, 3], r: "MONA: Morphine (cautiously), Oxygen (only if SpO2 <94%), Nitroglycerin, Aspirin. Amiodarone is not part of MONA but may be used for arrhythmias.", s: "Cardiovascular" },
  { q: "Select ALL post-MI lifestyle modifications the nurse should teach.", o: ["Cardiac rehabilitation enrollment", "Mediterranean-style diet low in saturated fat", "Complete bed rest for 6 months", "Smoking cessation", "Medication adherence education"], t: "sata", ca: [0, 1, 3, 4], r: "Post-MI teaching: cardiac rehab, heart-healthy diet, smoking cessation, medication adherence. Prolonged bed rest is harmful and not recommended.", s: "Cardiovascular" },
  { q: "A nurse has four post-MI patients. Which requires assessment FIRST?", o: ["Patient A: HR 62, BP 128/76, occasional PVCs", "Patient B: Sudden severe chest pain and ST re-elevation on monitor", "Patient C: Requesting pain medication for headache", "Patient D: Asking when they can eat"], a: 1, r: "Sudden severe chest pain with ST re-elevation suggests reinfarction or stent thrombosis — a life-threatening emergency requiring immediate assessment and intervention. The other patients have stable, non-emergent needs.", s: "Cardiovascular" },
  { q: "Which task can the RN delegate to an LPN for a post-MI patient?", o: ["Initial post-PCI assessment", "Monitoring vital signs on a stable patient 24 hours post-PCI", "Administering IV heparin drip adjustment", "Teaching about cardiac rehabilitation"], a: 1, r: "Monitoring vital signs on a stable patient is within LPN scope. Initial assessment, IV medication titration, and complex patient education require RN-level clinical judgment.", s: "Cardiovascular" },
  { q: "Which task can be delegated to a UAP for a cardiac patient?", o: ["Assessing chest pain", "Obtaining daily weights and vital signs", "Administering sublingual nitroglycerin", "Interpreting telemetry strips"], a: 1, r: "UAPs can perform routine vital signs and daily weights. Chest pain assessment, medication administration, and telemetry interpretation require nursing licensure.", s: "Cardiovascular" },
  { q: "A post-MI patient on day 2 develops pericardial friction rub, chest pain worsened by inspiration, and low-grade fever. What is the likely diagnosis?", o: ["Reinfarction", "Post-MI pericarditis (early)", "Pulmonary embolism", "Pneumonia"], a: 1, r: "Post-MI pericarditis occurs early (days 1-3) from direct pericardial inflammation. Dressler syndrome occurs later (weeks). Friction rub, pleuritic chest pain, and low-grade fever are classic. Treatment: aspirin (avoid NSAIDs early post-MI).", s: "Cardiovascular" },
  { q: "The nurse is preparing to administer ticagrelor. Which assessment is most important?", o: ["Check potassium level", "Verify aspirin dose is 81 mg (not 325 mg)", "Check BUN/creatinine", "Assess for latex allergy"], a: 1, r: "Ticagrelor effectiveness is reduced with aspirin doses >100 mg. The recommended combination is ticagrelor with aspirin 81 mg. Verifying the correct aspirin dose is critical for optimal antiplatelet effect.", s: "Cardiovascular" },
  { q: "What is the significance of Killip Class IV in acute MI?", o: ["No heart failure signs", "Mild crackles present", "Pulmonary edema", "Cardiogenic shock — highest mortality"], a: 3, r: "Killip IV = cardiogenic shock. Classification: I (no HF), II (crackles/S3), III (pulmonary edema), IV (cardiogenic shock with SBP <90). Class IV carries >40% mortality.", s: "Cardiovascular" },
  { q: "A nurse is monitoring a patient on IV heparin for NSTEMI. The aPTT is 110 seconds (target 60-80). What action is appropriate?", o: ["Continue the infusion", "Stop the infusion and notify the provider per protocol", "Double the rate", "Administer vitamin K"], a: 1, r: "aPTT of 110 seconds is supratherapeutic, increasing hemorrhage risk. Per heparin protocol, stop the infusion, notify the provider, and recheck aPTT. Protamine is reserved for active bleeding. Vitamin K reverses warfarin, not heparin.", s: "Cardiovascular" },
  { q: "What laboratory value change confirms reinfarction in a patient who already had elevated troponin from the initial MI?", o: ["Any troponin above normal", "A 20% increase in troponin above a declining baseline level", "CK-MB re-elevation (rises and falls faster, showing a new peak)", "Rising BNP"], a: 2, r: "CK-MB is preferred for detecting reinfarction because it rises and falls faster than troponin. A new peak in CK-MB suggests acute reinfarction. Troponin may remain elevated for 1-2 weeks from the initial event.", s: "Cardiovascular" },
  { q: "An MI patient suddenly develops PEA arrest on day 5. What mechanical complication is most likely?", o: ["VSD", "Free wall rupture with cardiac tamponade", "Papillary muscle dysfunction", "Ventricular aneurysm"], a: 1, r: "Sudden PEA arrest days 3-7 post-MI suggests free wall rupture: necrotic myocardium ruptures, blood fills the pericardium, causing acute tamponade and electromechanical dissociation (PEA). Mortality is >90%.", s: "Cardiovascular" },
  { q: "A patient with NSTEMI is on aspirin, clopidogrel, and enoxaparin. Which lab must be monitored?", o: ["aPTT", "Platelet count and hemoglobin", "INR", "Fibrinogen only"], a: 1, r: "Triple antithrombotic therapy increases bleeding risk. Monitor platelet count (for HIT with heparin products), hemoglobin (for occult bleeding), and assess for signs of hemorrhage. Enoxaparin does not require aPTT monitoring (unlike unfractionated heparin).", s: "Cardiovascular" },
  { q: "Which statement indicates the patient needs MORE teaching about post-MI care?", o: ["I will take my aspirin every day", "I can resume all activities immediately without restriction", "I will call 911 if I have chest pain", "I will attend cardiac rehabilitation"], a: 1, r: "Immediate unrestricted activity is inappropriate post-MI. Activity should be gradually increased through cardiac rehabilitation. Other statements demonstrate appropriate understanding.", s: "Cardiovascular" },
  { q: "A patient develops cardiogenic shock 6 hours after anterior STEMI. CI is 1.5 L/min/m². What intervention takes HIGHEST priority?", o: ["IV furosemide bolus", "Emergent repeat cardiac catheterization", "Oral beta-blocker", "Position change to Trendelenburg"], a: 1, r: "Emergent revascularization is the single most important intervention for MI-related cardiogenic shock. IV diuretics may help with congestion but don't address the root cause. Beta-blockers are contraindicated in acute cardiogenic shock.", s: "Cardiovascular" },
  { q: "What medication prevents adverse ventricular remodeling post-MI?", o: ["Aspirin", "ACE inhibitor", "Morphine", "Oxygen"], a: 1, r: "ACE inhibitors prevent ventricular remodeling by blocking angiotensin II-mediated fibrosis and hypertrophy. Indicated within 24 hours for anterior MI or EF <40%. They reduce HF development and mortality post-MI.", s: "Cardiovascular" },
  { q: "A nurse notes a patient's cardiac monitor shows accelerated idioventricular rhythm at 75 bpm after successful PCI. BP is 120/78. What should the nurse do?", o: ["Call a code blue", "Administer amiodarone", "Continue monitoring — this is a benign reperfusion arrhythmia", "Prepare for cardioversion"], a: 2, r: "AIVR (rate 60-100 bpm) is a benign, self-limiting reperfusion arrhythmia indicating successful PCI. No treatment needed if hemodynamically stable. It typically resolves spontaneously.", s: "Cardiovascular" },
  { q: "Which patients receive morphine cautiously in acute MI?", o: ["All MI patients receive morphine routinely", "Patients with ongoing pain despite NTG — use cautiously due to hypotension and respiratory depression risks", "Only patients under 40", "Morphine is never used in MI"], a: 1, r: "Morphine is no longer routine for MI due to concerns about vasodilation (hypotension), respiratory depression, and potential interference with P2Y12 inhibitor absorption. Use cautiously only for pain refractory to nitrates.", s: "Cardiovascular" },
  { q: "What ECG change distinguishes STEMI from NSTEMI?", o: ["T-wave inversion", "ST segment elevation ≥1 mm in ≥2 contiguous leads", "Prolonged QT interval", "Left bundle branch block"], a: 1, r: "STEMI requires ST elevation ≥1 mm in ≥2 contiguous leads, indicating transmural ischemia requiring emergent reperfusion. NSTEMI shows ST depression, T-wave inversion, or no ECG changes with positive troponin.", s: "Cardiovascular" },
  { q: "A patient's 12-lead ECG shows reciprocal ST depression in leads I and aVL with ST elevation in II, III, aVF. What does this suggest?", o: ["Anterior MI", "Inferior MI with reciprocal changes", "Lateral MI", "Posterior MI"], a: 1, r: "ST elevation in II, III, aVF = inferior MI. Reciprocal ST depression in I, aVL confirms ischemia involving the inferior wall. Reciprocal changes support the diagnosis and may indicate larger infarct territory.", s: "Cardiovascular" },
  { q: "Which CK-MB pattern helps diagnose reinfarction?", o: ["Stable elevation for 2 weeks", "A new peak in CK-MB levels after initial decline", "CK-MB below normal", "Only troponin is useful"], a: 1, r: "CK-MB rises at 4-6 hours, peaks at 12-24 hours, and normalizes by 48-72 hours (faster kinetics than troponin). A new CK-MB peak after initial decline suggests reinfarction — a crucial monitoring advantage over troponin.", s: "Cardiovascular" },
  { q: "A patient with chest pain and ST elevation calls the nurse. Door-to-balloon goal for primary PCI is:", o: ["30 minutes", "60 minutes", "90 minutes", "120 minutes"], a: 2, r: "AHA/ACC guidelines: door-to-balloon time for primary PCI should be <90 minutes from first medical contact. For transfer patients, total ischemic time goal is <120 minutes.", s: "Cardiovascular" },
  { q: "A post-MI patient develops sudden severe shortness of breath and pink frothy sputum. What complication is this?", o: ["Pneumonia", "Acute pulmonary edema from LV failure", "Asthma exacerbation", "Aspiration"], a: 1, r: "Pink frothy sputum = acute pulmonary edema from LV failure post-MI. Elevated LV end-diastolic pressure forces fluid into alveoli. Requires emergent IV diuretics, oxygen, and possibly NIPPV/intubation.", s: "Cardiovascular" },
  { q: "Which ECG finding suggests posterior MI?", o: ["Tall R waves and ST depression in V1-V3", "ST elevation in V1-V4", "ST elevation in II, III, aVF only", "Normal ECG"], a: 0, r: "Posterior MI shows reciprocal changes in anterior leads: tall R waves (mirror image of Q waves) and ST depression in V1-V3. Posterior leads (V7-V9) will show ST elevation. Often occurs with inferior MI.", s: "Cardiovascular" },
  { q: "When should dual antiplatelet therapy be started in ACS?", o: ["Only after PCI is completed", "As soon as possible — aspirin + P2Y12 inhibitor at presentation", "After discharge from hospital", "Only if stent is placed"], a: 1, r: "Dual antiplatelet therapy (aspirin + P2Y12 inhibitor) should be started at ACS presentation to prevent further platelet-mediated thrombus growth. Loading doses given before PCI improve outcomes.", s: "Cardiovascular" },
  { q: "A type 2 MI differs from type 1 MI because:", o: ["Both are caused by plaque rupture", "Type 2 is caused by supply-demand mismatch (anemia, tachycardia, sepsis) without plaque rupture", "Type 2 is always benign", "Type 2 requires PCI"], a: 1, r: "Type 1 MI: atherosclerotic plaque rupture/erosion with thrombosis. Type 2 MI: myocardial oxygen supply-demand mismatch from other conditions (severe anemia, profound hypotension, tachyarrhythmia, sepsis). Treatment addresses the underlying cause, not revascularization.", s: "Cardiovascular" },
  { q: "A patient post-MI asks why they need to take a statin when their cholesterol is 'normal.' The best response is:", o: ["You can stop the statin if cholesterol is normal", "Statins stabilize plaques and reduce inflammation beyond just lowering cholesterol, preventing future heart attacks", "Statins are only for high cholesterol", "Your doctor made an error"], a: 1, r: "Statins have pleiotropic effects: plaque stabilization, anti-inflammatory properties, and endothelial function improvement. These benefits reduce cardiovascular events regardless of baseline cholesterol level.", s: "Cardiovascular" },
  { q: "A nurse is discharging a post-MI patient. Which medication combination represents optimal secondary prevention?", o: ["Aspirin only", "Aspirin, high-intensity statin, beta-blocker, ACEi/ARB", "Calcium channel blocker and diuretic only", "Nitroglycerin and warfarin"], a: 1, r: "Optimal post-MI secondary prevention: aspirin (antiplatelet) + high-intensity statin (plaque stabilization, lipid lowering) + beta-blocker (reduce O2 demand, prevent arrhythmias) + ACEi/ARB (prevent remodeling, especially if anterior MI or EF <40%).", s: "Cardiovascular" },

  // ===== HEART FAILURE (Questions 41-80) =====
  { q: "A patient with HFrEF (EF 22%) presents with bilateral crackles, JVD, and 3+ pitting edema. Which medication class provides the MOST immediate symptom relief?", o: ["Beta-blocker", "Loop diuretic (furosemide)", "ACE inhibitor", "SGLT2 inhibitor"], a: 1, r: "Loop diuretics provide immediate symptomatic relief by promoting sodium and water excretion, reducing preload and pulmonary congestion. While GDMT (ACEi, BB, MRA, SGLT2i) improves outcomes, diuretics are the acute symptomatic treatment.", s: "Cardiovascular" },
  { q: "Which heart sound is associated with volume overload in HFrEF?", o: ["S1", "S2", "S3 gallop", "S4 gallop"], a: 2, r: "S3 is caused by rapid ventricular filling into a dilated, volume-overloaded ventricle. It is pathognomonic for HFrEF (systolic failure). S4 results from forceful atrial contraction against a stiff ventricle (HFpEF/diastolic failure).", s: "Cardiovascular" },
  { q: "A patient with HFpEF develops new atrial fibrillation and acute decompensation. Why is AF especially dangerous in HFpEF?", o: ["AF always causes MI", "Loss of atrial kick reduces ventricular filling by 20-30% in an already stiff ventricle", "AF has no effect on HFpEF", "AF causes hypertension"], a: 1, r: "The stiff, noncompliant ventricle in HFpEF relies heavily on the atrial kick for adequate filling. AF eliminates this contribution, causing disproportionate hemodynamic compromise.", s: "Cardiovascular" },
  { q: "A patient with HFrEF has sodium of 128 mEq/L. What does this indicate?", o: ["Sodium depletion requiring IV normal saline", "Dilutional hyponatremia from excess water retention — managed with fluid restriction", "Renal failure", "Medication error"], a: 1, r: "Hyponatremia in HF is dilutional (too much water, not too little sodium). Treatment: fluid restriction 1.5 L/day. IV NS would worsen volume overload. Hyponatremia (<130) is a poor prognostic indicator.", s: "Cardiovascular" },
  { q: "Which BNP level supports a diagnosis of heart failure?", o: ["BNP <50 pg/mL", "BNP >400 pg/mL", "BNP 50-100 pg/mL", "BNP is not useful for HF"], a: 1, r: "BNP >400 pg/mL strongly supports HF diagnosis. BNP <100 pg/mL makes HF unlikely. Values between 100-400 are indeterminate. NT-proBNP >900 pg/mL also supports HF.", s: "Cardiovascular" },
  { q: "The patient gained 4 pounds overnight on daily weight monitoring. What should the nurse do?", o: ["Document and reassess tomorrow", "Notify the provider — weight gain >2 lbs/day indicates fluid retention", "Restrict protein intake", "Increase activity"], a: 1, r: "Weight gain >2 lbs/day or >5 lbs/week indicates fluid retention and possible decompensation. 1 kg ≈ 1 L of fluid. The provider should be notified for possible diuretic adjustment.", s: "Cardiovascular" },
  { q: "Select ALL components of the four pillars of GDMT for HFrEF.", o: ["ACEi/ARB/ARNI", "Evidence-based beta-blocker", "Mineralocorticoid receptor antagonist", "SGLT2 inhibitor", "Calcium channel blocker"], t: "sata", ca: [0, 1, 2, 3], r: "Four pillars: ACEi/ARB/ARNI + beta-blocker (carvedilol/metoprolol succinate/bisoprolol) + MRA (spironolactone/eplerenone) + SGLT2i. Each independently reduces mortality. Calcium channel blockers are NOT included.", s: "Cardiovascular" },
  { q: "Select ALL signs of left-sided heart failure.", o: ["Crackles on lung auscultation", "Dyspnea on exertion", "Peripheral edema", "Orthopnea and PND", "Hepatomegaly"], t: "sata", ca: [0, 1, 3], r: "Left-sided HF causes pulmonary congestion: crackles, dyspnea, orthopnea, PND, tachypnea. Peripheral edema and hepatomegaly are right-sided HF findings.", s: "Cardiovascular" },
  { q: "Select ALL signs of right-sided heart failure.", o: ["JVD", "Peripheral edema", "Crackles", "Hepatomegaly", "Ascites"], t: "sata", ca: [0, 1, 3, 4], r: "Right-sided HF causes systemic venous congestion: JVD, peripheral edema, hepatomegaly, ascites, weight gain. Crackles indicate left-sided (pulmonary) congestion.", s: "Cardiovascular" },
  { q: "Select ALL correct statements about sacubitril/valsartan (Entresto).", o: ["Requires 36-hour washout from ACEi before starting", "Monitor with NT-proBNP (not BNP)", "Superior to enalapril in reducing HF mortality", "Can be given with ACEi simultaneously", "Risk of angioedema"], t: "sata", ca: [0, 1, 2, 4], r: "Entresto requires 36-hour ACEi washout (angioedema risk), is monitored with NT-proBNP (neprilysin inhibition falsely elevates BNP), and was superior to enalapril in the PARADIGM-HF trial.", s: "Cardiovascular" },
  { q: "Select ALL appropriate nursing interventions for acute decompensated HF.", o: ["Position in high-Fowler's", "Administer IV loop diuretics", "Monitor strict I&O", "Encourage high-sodium diet", "Apply oxygen if SpO2 <94%"], t: "sata", ca: [0, 1, 2, 4], r: "High-Fowler's reduces venous return and eases breathing. IV diuretics address congestion. Strict I&O and SpO2 monitoring are essential. High-sodium diet would worsen fluid retention.", s: "Cardiovascular" },
  { q: "A nurse is prioritizing four HF patients. Which should be assessed FIRST?", o: ["HFrEF patient on stable GDMT asking about diet", "HFpEF patient with HR 78 and BP 130/82", "HFrEF patient with new-onset dyspnea at rest and SpO2 88%", "HF patient who gained 1 pound since yesterday"], a: 2, r: "New-onset dyspnea at rest with SpO2 88% indicates acute decompensation — a potentially life-threatening situation requiring immediate assessment, oxygen, and likely IV diuretics.", s: "Cardiovascular" },
  { q: "Which task can be delegated to a UAP for a patient with heart failure?", o: ["Administering IV furosemide", "Assessing breath sounds", "Measuring daily weight and recording I&O", "Teaching about sodium restriction"], a: 2, r: "Daily weights and I&O recording are routine tasks within UAP scope. Medication administration, physical assessment, and complex patient education require nursing licensure.", s: "Cardiovascular" },
  { q: "What is the primary goal of furosemide therapy in acute HF?", o: ["Lower blood pressure", "Reduce preload and relieve pulmonary congestion through diuresis", "Increase cardiac contractility", "Prevent arrhythmias"], a: 1, r: "Loop diuretics reduce preload by promoting renal excretion of sodium and water, decreasing intravascular volume and relieving pulmonary congestion. They do not directly improve contractility.", s: "Cardiovascular" },
  { q: "Why must potassium be monitored closely when a patient is on furosemide?", o: ["Furosemide causes hyperkalemia", "Furosemide causes hypokalemia by increasing renal potassium excretion", "Potassium is unaffected by diuretics", "Only magnesium matters"], a: 1, r: "Loop diuretics increase potassium excretion at the loop of Henle, risking hypokalemia. Low K+ causes dangerous cardiac arrhythmias. Replace K+ as ordered and monitor magnesium (hypomagnesemia worsens hypokalemia).", s: "Cardiovascular" },
  { q: "A patient on carvedilol for HFrEF reports increased fatigue and dizziness. HR is 48 bpm. What should the nurse do?", o: ["Continue the medication as prescribed", "Hold the dose and notify the provider — symptomatic bradycardia", "Increase the dose", "Administer caffeine"], a: 1, r: "Carvedilol (beta-blocker) can cause significant bradycardia. HR 48 with symptoms (fatigue, dizziness) requires holding the dose and provider notification for potential dose reduction or medication change.", s: "Cardiovascular" },
  { q: "What is the recommended fluid restriction for HF patients with hyponatremia?", o: ["No restriction needed", "1.5-2 L/day", "500 mL/day", "4 L/day"], a: 1, r: "Fluid restriction of 1.5-2 L/day is recommended when sodium is <130 mEq/L. This addresses dilutional hyponatremia. Patients should be taught to include all fluids (ice chips, liquid medications, soups) in their daily allowance.", s: "Cardiovascular" },
  { q: "A patient with HFrEF is being considered for ICD placement. What is the main indication?", o: ["EF ≤35% despite 3 months of optimal GDMT for primary prevention of sudden cardiac death", "EF >50%", "Asymptomatic with normal EF", "Only after a cardiac arrest"], a: 0, r: "Primary prevention ICD is indicated for HFrEF with EF ≤35% despite at least 3 months of optimal GDMT (to allow for potential EF recovery). ICD prevents sudden cardiac death from ventricular arrhythmias.", s: "Cardiovascular" },
  { q: "What is diuretic resistance and how is it managed?", o: ["Giving more of the same diuretic only", "Inadequate response to diuretics — managed by adding a thiazide (metolazone) for sequential nephron blockade", "Switching to oral intake only", "Discontinuing all diuretics"], a: 1, r: "Diuretic resistance = poor response to adequate loop diuretic doses. Management: sequential nephron blockade (add metolazone 30 min before loop diuretic), IV bolus + continuous infusion, or consider ultrafiltration for refractory cases.", s: "Cardiovascular" },
  { q: "A patient on milrinone develops rapid irregular heartbeat. What should the nurse do?", o: ["Continue infusion and reassess in 1 hour", "Notify provider — ventricular arrhythmias are a known milrinone complication", "Increase the rate", "This is an expected therapeutic effect"], a: 1, r: "Milrinone increases intracellular cAMP, which can trigger ventricular arrhythmias (VT/VF). New arrhythmia requires immediate provider notification, continuous monitoring, and possible dose adjustment or discontinuation.", s: "Cardiovascular" },
  { q: "What assessment finding differentiates HFrEF from HFpEF on echocardiogram?", o: ["Heart rate", "Ejection fraction: HFrEF ≤40%, HFpEF ≥50%", "Heart size is the same in both", "Blood pressure response"], a: 1, r: "EF distinguishes: HFrEF (systolic) has EF ≤40% with dilated ventricle. HFpEF (diastolic) has EF ≥50% with thick, stiff ventricle. HFmrEF (midrange) has EF 41-49%. Treatment strategies differ.", s: "Cardiovascular" },
  { q: "Which statement by a HF patient indicates understanding of self-management?", o: ["I weigh myself once a week", "I weigh myself every morning on the same scale and call my doctor if I gain more than 2 pounds in a day", "I can eat as much sodium as I want", "I will stop my medications when I feel better"], a: 1, r: "Daily weight monitoring at the same time on the same scale is the most sensitive indicator of fluid status. Weight gain >2 lbs/day or >5 lbs/week requires provider notification.", s: "Cardiovascular" },
  { q: "A nurse is teaching about common HF decompensation triggers. Which triggers should be included?", o: ["Dietary sodium excess", "Medication non-adherence", "New infection", "New arrhythmia (especially AF)", "All of the above"], a: 4, r: "All listed are common decompensation triggers. Dietary indiscretion and medication non-adherence are the most common. Others: infection, arrhythmia, uncontrolled HTN, anemia, and thyroid disease.", s: "Cardiovascular" },
  { q: "What stage in ACC/AHA HF staging describes a patient with structural heart disease and current symptoms?", o: ["Stage A", "Stage B", "Stage C", "Stage D"], a: 2, r: "Stage C = structural heart disease with current or prior HF symptoms. Stage A = at risk without structural disease. Stage B = structural disease without symptoms. Stage D = refractory HF needing advanced therapies. Staging is irreversible.", s: "Cardiovascular" },
  { q: "What is the purpose of spironolactone in HFrEF management?", o: ["Only to replace potassium", "Blocks aldosterone receptors, reducing sodium/water retention and myocardial fibrosis — reduced mortality by 30% in RALES trial", "As a primary diuretic", "To increase blood pressure"], a: 1, r: "Spironolactone is an MRA that blocks aldosterone's effects: reducing fluid retention, preventing myocardial fibrosis, and reducing mortality by 30% (RALES trial). It is one of the four pillars of GDMT.", s: "Cardiovascular" },
  { q: "A patient with newly diagnosed HFrEF asks about exercise. What is the nurse's best response?", o: ["You should avoid all physical activity", "Cardiac rehabilitation with supervised exercise is recommended and improves outcomes", "Only rest will help", "Exercise when you feel like it without guidance"], a: 1, r: "Cardiac rehabilitation is recommended for stable HF patients. Supervised exercise improves functional capacity, quality of life, and may reduce hospitalizations. Exercise should be gradually increased under professional guidance.", s: "Cardiovascular" },
  { q: "A patient with HFrEF is on high-dose furosemide. The potassium level is 3.1 mEq/L. What is the priority action?", o: ["Continue monitoring", "Hold furosemide, notify provider, and anticipate potassium replacement", "Encourage potassium-rich foods only", "Increase furosemide dose"], a: 1, r: "K+ 3.1 is significantly hypokalemic (normal 3.5-5.0) and dangerous in HF (arrhythmia risk, digoxin toxicity risk). Hold the loop diuretic causing potassium loss, notify provider, and anticipate IV or oral potassium replacement.", s: "Cardiovascular" },
  { q: "A patient on GDMT for HFrEF has an EF that improved from 25% to 42%. Should medications be stopped?", o: ["Yes, the EF is improved so medications are no longer needed", "No — continue GDMT as improvement is medication-dependent; stopping risks decompensation", "Switch to calcium channel blockers", "Reduce all doses by half"], a: 1, r: "GDMT should be continued even if EF improves because improvement is medication-dependent. Stopping neurohormonal blockers leads to recurrent remodeling and decompensation. Staging is irreversible (still Stage C).", s: "Cardiovascular" },
  { q: "What is the Nohria-Stevenson classification for acute HF?", o: ["Based on EF only", "Classifies patients as warm/cold (perfusion) and wet/dry (congestion)", "Based on age and gender", "A medication dosing guide"], a: 1, r: "Nohria-Stevenson profiles: Warm-Dry (compensated), Warm-Wet (congested but perfusing — most common, treat with diuretics), Cold-Dry (need fluids), Cold-Wet (cardiogenic shock — worst prognosis, needs inotropes/pressors).", s: "Cardiovascular" },
  { q: "What is the significance of a BNP that decreases during hospitalization for HF?", o: ["No clinical significance", "Indicates response to treatment and favorable prognosis", "Indicates worsening HF", "Requires medication discontinuation"], a: 1, r: "Declining BNP during HF treatment indicates reduced ventricular wall stress from effective decongestion. It correlates with improved outcomes. BNP trending guides prognosis but should not be used to titrate diuretics day-to-day.", s: "Cardiovascular" },

  // ===== CORONARY ARTERY DISEASE (Questions 81-120) =====
  { q: "A patient with stable angina reports chest discomfort that now occurs at rest and is not relieved by nitroglycerin. What has this angina progressed to?", o: ["Stable angina — no change", "Unstable angina — requires ACS evaluation", "Prinzmetal angina", "Non-cardiac pain"], a: 1, r: "Angina occurring at rest, of new onset, or with a crescendo pattern = unstable angina. This represents an acute coronary syndrome requiring emergent evaluation: ECG, serial troponins, and possible cardiac catheterization.", s: "Cardiovascular" },
  { q: "What is the primary mechanism of action of statins?", o: ["Block calcium channels", "Inhibit HMG-CoA reductase, reducing hepatic cholesterol synthesis", "Block platelet aggregation", "Reduce blood pressure"], a: 1, r: "Statins inhibit HMG-CoA reductase, the rate-limiting enzyme in cholesterol synthesis. This upregulates hepatic LDL receptors, increasing LDL clearance from blood. Additional pleiotropic effects include plaque stabilization and anti-inflammatory activity.", s: "Cardiovascular" },
  { q: "A patient on atorvastatin reports bilateral thigh pain that began 2 weeks after starting the medication. What should the nurse recommend?", o: ["Continue medication and exercise more", "Report myalgia to the provider for CK level check and possible medication adjustment", "Stop the statin immediately without telling the provider", "Take ibuprofen for the pain"], a: 1, r: "New muscle pain after statin initiation requires evaluation: CK level to rule out rhabdomyolysis. Myalgia occurs in 5-10% of patients. The provider may adjust the dose, switch statins, or consider alternatives.", s: "Cardiovascular" },
  { q: "What lifestyle modification has the greatest impact on reducing CAD progression?", o: ["Taking vitamins", "Smoking cessation", "Sleeping more", "Stress reduction alone"], a: 1, r: "Smoking cessation provides the most dramatic risk reduction. Excess cardiac risk drops 50% within 1 year of quitting. Smoking causes endothelial damage, promotes thrombosis, induces vasospasm, and increases oxidative stress.", s: "Cardiovascular" },
  { q: "Nitroglycerin relieves angina primarily by which mechanism?", o: ["Increasing heart rate", "Venodilation reducing preload, thereby decreasing myocardial oxygen demand", "Improving hemoglobin function", "Blocking calcium channels"], a: 1, r: "NTG → nitric oxide → cGMP → vascular smooth muscle relaxation. Primary effect: venodilation (reduces preload/wall stress). Secondary: arterial dilation (reduces afterload) and coronary artery dilation. Net effect: decreased myocardial O2 demand.", s: "Cardiovascular" },
  { q: "Before administering NTG, the nurse should verify:", o: ["Blood glucose level", "SBP is at least 90 mmHg and no recent PDE5 inhibitor use", "Potassium level", "Patient's weight"], a: 1, r: "NTG is contraindicated with SBP <90 (vasodilation worsens hypotension) and within 24-48 hours of PDE5 inhibitors (synergistic vasodilation → severe hypotension). Also avoid in RV infarction and severe aortic stenosis.", s: "Cardiovascular" },
  { q: "A patient presents with predictable exertional chest discomfort that has been unchanged for 8 months. Exercise stress test shows 2mm ST depression. What is the diagnosis?", o: ["Acute MI", "Stable angina with exercise-induced ischemia", "Unstable angina", "Pericarditis"], a: 1, r: "Predictable, reproducible chest discomfort with exertion + ST depression on stress test = stable angina with demonstrable ischemia. The 8-month stable pattern excludes unstable angina. Requires risk factor modification and anti-anginal therapy.", s: "Cardiovascular" },
  { q: "The endothelial dysfunction theory of atherosclerosis states:", o: ["Atherosclerosis begins with vein damage", "Risk factors damage the endothelial lining, reducing NO production and increasing LDL infiltration", "Atherosclerosis is caused by infection only", "Endothelium plays no role in CAD"], a: 1, r: "Cardiovascular risk factors damage endothelial cells, reducing protective nitric oxide production and increasing permeability to LDL particles. This initiates the inflammatory cascade of atherosclerosis.", s: "Cardiovascular" },
  { q: "A patient with known CAD should maintain LDL below what level?", o: ["<130 mg/dL", "<100 mg/dL", "<70 mg/dL for established CAD", "<200 mg/dL"], a: 2, r: "For established CAD (secondary prevention), the LDL goal is <70 mg/dL. Very high-risk patients may target <55 mg/dL. High-intensity statin therapy is the cornerstone of achieving this goal.", s: "Cardiovascular" },
  { q: "Select ALL modifiable risk factors for coronary artery disease.", o: ["Hypertension", "Family history of premature CAD", "Diabetes mellitus", "Tobacco use", "Age >55"], t: "sata", ca: [0, 2, 3], r: "Modifiable: hypertension, diabetes, tobacco use, dyslipidemia, obesity, physical inactivity. Non-modifiable: family history, age, sex. Risk factor modification is the foundation of CAD prevention.", s: "Cardiovascular" },
  { q: "Select ALL appropriate components of CAD patient education.", o: ["Mediterranean-style diet", "Smoking cessation counseling", "NTG use: take 1 tablet, call 911 if no relief in 5 minutes", "Unlimited sodium intake", "Regular exercise as tolerated"], t: "sata", ca: [0, 1, 2, 4], r: "CAD education includes heart-healthy diet, smoking cessation, proper NTG use (current guideline: 1 tab → 911 if not relieved in 5 min), and regular exercise. Sodium should be limited, not unlimited.", s: "Cardiovascular" },
  { q: "Select ALL pleiotropic effects of statins beyond lipid lowering.", o: ["Plaque stabilization", "Anti-inflammatory effect (reduces hs-CRP)", "Improved endothelial function", "Increased blood glucose", "Antithrombotic effect"], t: "sata", ca: [0, 1, 2, 4], r: "Statin pleiotropic effects: plaque stabilization, anti-inflammatory, endothelial improvement, antithrombotic properties. Increased blood glucose is a side effect, not a pleiotropic benefit.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients with chest pain. Which should be assessed FIRST?", o: ["Patient with stable angina awaiting stress test", "Patient with new-onset rest angina and diaphoresis", "Patient with musculoskeletal chest wall tenderness", "Patient with GERD-related chest burning"], a: 1, r: "New-onset rest angina with diaphoresis suggests ACS — potentially life-threatening. This patient requires immediate ECG, troponin, and monitoring. The others have stable or non-cardiac conditions.", s: "Cardiovascular" },
  { q: "Which task can an LPN perform for a patient with stable angina?", o: ["Perform initial cardiac assessment", "Administer scheduled oral medications", "Titrate IV nitroglycerin drip", "Develop the care plan"], a: 1, r: "LPNs can administer scheduled oral medications to stable patients. Initial assessment, IV medication titration, and care plan development are RN responsibilities.", s: "Cardiovascular" },
  { q: "A patient asks why they need to have a 10-12 hour nitrate-free interval. The nurse explains:", o: ["To save money on medication", "Continuous nitrate exposure causes tolerance, reducing effectiveness. The drug-free interval prevents this", "Nitrates are only needed during the day", "There is no evidence for this practice"], a: 1, r: "Pharmacological nitrate tolerance develops with continuous exposure through depletion of sulfhydryl groups needed for nitric oxide generation. A 10-12 hour daily interval (usually overnight) prevents tolerance.", s: "Cardiovascular" },
  { q: "Foam cell formation in atherosclerosis involves:", o: ["Red blood cells accumulating in the vessel wall", "Macrophages engulfing oxidized LDL via scavenger receptors", "Platelets forming thrombus", "Smooth muscle cell contraction"], a: 1, r: "Monocytes enter the subendothelial space, differentiate into macrophages, and engulf oxidized LDL via scavenger receptors (CD36, SR-A) that are not subject to negative feedback regulation. The resulting lipid-laden macrophages = foam cells, the building blocks of fatty streaks.", s: "Cardiovascular" },
  { q: "What characteristics make an atherosclerotic plaque 'vulnerable' to rupture?", o: ["Thick fibrous cap", "Thin fibrous cap, large lipid core, and active inflammation", "Small size", "Heavy calcification"], a: 1, r: "Vulnerable plaques: thin fibrous cap (<65 μm), large lipid-rich necrotic core, abundant inflammatory cells (macrophages releasing MMPs that degrade the cap). These features increase rupture risk, causing ACS.", s: "Cardiovascular" },
  { q: "What is the role of matrix metalloproteinases (MMPs) in plaque rupture?", o: ["They stabilize plaques", "They degrade the fibrous cap collagen, weakening it and promoting rupture", "They reduce inflammation", "They form blood clots"], a: 1, r: "MMPs are proteolytic enzymes released by activated macrophages within atherosclerotic plaques. They degrade collagen and elastin in the fibrous cap, thinning and weakening it until mechanical stress causes rupture.", s: "Cardiovascular" },
  { q: "Which imaging modality is the gold standard for defining coronary artery anatomy and stenosis severity?", o: ["Exercise stress test", "Echocardiogram", "Coronary angiography (cardiac catheterization)", "Chest X-ray"], a: 2, r: "Coronary angiography (cardiac catheterization) provides direct visualization of coronary artery anatomy, stenosis severity, and guides revascularization decisions (PCI vs CABG). It is both diagnostic and potentially therapeutic.", s: "Cardiovascular" },
  { q: "Why are women more likely to have atypical presentations of CAD and MI?", o: ["Women don't get heart disease", "Women more often have microvascular disease, present with fatigue, dyspnea, nausea rather than classic chest pressure", "Gender has no effect on presentation", "Women always present with chest pain"], a: 1, r: "Women have higher rates of microvascular disease (vs large vessel), endothelial dysfunction, and coronary vasospasm. They more often present atypically: fatigue, dyspnea, nausea, jaw/back pain, or epigastric discomfort instead of classic substernal pressure.", s: "Cardiovascular" },
  { q: "A patient with angina asks about cardiac rehabilitation. What should the nurse explain?", o: ["It is only for post-MI patients", "It provides supervised exercise, education, and psychosocial support to improve cardiovascular fitness and reduce risk factors", "It is optional and provides no benefit", "It replaces all medications"], a: 1, r: "Cardiac rehabilitation is an evidence-based program of supervised exercise, risk factor education, dietary counseling, and psychosocial support. It reduces mortality, improves functional capacity, and enhances quality of life. Recommended for angina, post-MI, and post-CABG patients.", s: "Cardiovascular" },

  // ===== CARDIOGENIC SHOCK (Questions 121-160) =====
  { q: "A patient with massive anterior STEMI develops SBP 74/48, HR 124, CI 1.4, PCWP 26, SVR 2100. What type of shock is this?", o: ["Septic shock", "Cardiogenic shock", "Hypovolemic shock", "Neurogenic shock"], a: 1, r: "Low CI + high PCWP + high SVR = cardiogenic shock. Septic would have low SVR/high CI. Hypovolemic would have low PCWP. Neurogenic would have low SVR with bradycardia.", s: "Cardiovascular" },
  { q: "What is the mortality rate of cardiogenic shock even with modern therapy?", o: ["5-10%", "15-20%", "40-50%", "90-100%"], a: 2, r: "Despite advances in PCI, mechanical support, and critical care, cardiogenic shock still carries 40-50% mortality. Early revascularization reduces mortality from >70% to approximately 50%.", s: "Cardiovascular" },
  { q: "What lactate level is associated with significantly higher mortality in cardiogenic shock?", o: [">1 mmol/L", ">2 mmol/L", ">4 mmol/L", ">10 mmol/L"], a: 2, r: "Lactate >4 mmol/L indicates severe tissue hypoperfusion and is associated with significantly higher mortality in cardiogenic shock. Lactate clearance (>10% in 2 hours) is a more useful resuscitation target than absolute values.", s: "Cardiovascular" },
  { q: "Select ALL hemodynamic findings consistent with cardiogenic shock.", o: ["CI <1.8 L/min/m²", "PCWP >18 mmHg", "SVR elevated", "SBP <90 mmHg for >30 minutes", "Low SVR"], t: "sata", ca: [0, 1, 2, 3], r: "Cardiogenic shock profile: low CI (<1.8), high PCWP (>18, congestion), high SVR (compensatory vasoconstriction), and persistent hypotension. Low SVR is characteristic of septic/distributive shock.", s: "Cardiovascular" },
  { q: "Select ALL clinical signs of cardiogenic shock.", o: ["Cool, mottled extremities", "Altered mental status", "Oliguria", "Warm, flushed skin", "Bilateral crackles"], t: "sata", ca: [0, 1, 2, 4], r: "Cardiogenic shock: cool/mottled skin (vasoconstriction), AMS (cerebral hypoperfusion), oliguria (renal hypoperfusion), and crackles (pulmonary edema). Warm, flushed skin indicates distributive/septic shock.", s: "Cardiovascular" },
  { q: "Select ALL appropriate interventions for cardiogenic shock.", o: ["Emergent PCI for MI-related shock", "Norepinephrine for MAP support", "Dobutamine or milrinone for inotropy", "Aggressive IV fluid bolus", "Mechanical circulatory support consideration"], t: "sata", ca: [0, 1, 2, 4], r: "Cardiogenic shock management: revascularization, vasopressors (norepinephrine first-line), inotropes, and mechanical support (IABP, Impella, ECMO). Aggressive IV fluids worsen pulmonary edema in already congested patients.", s: "Cardiovascular" },
  { q: "A nurse is managing a patient on norepinephrine via peripheral IV. The site becomes swollen and blanched. What should the nurse do?", o: ["Continue the infusion", "Stop the infusion, inject phentolamine locally, and notify the provider", "Apply warm compress only", "Increase the rate"], a: 1, r: "Norepinephrine extravasation causes tissue ischemia and necrosis from vasoconstriction. Stop immediately, inject phentolamine (alpha-blocker) locally to reverse vasoconstriction. Vasopressors should be given via central line.", s: "Cardiovascular" },
  { q: "Which shock type is characterized by warm, flushed skin with hypotension?", o: ["Cardiogenic shock", "Hypovolemic shock", "Septic (distributive) shock", "Obstructive shock"], a: 2, r: "Septic shock causes inappropriate vasodilation (warm skin) from inflammatory mediators and nitric oxide. Cardiogenic and hypovolemic cause vasoconstriction (cool skin). This clinical distinction guides initial management.", s: "Cardiovascular" },
  { q: "A patient in cardiogenic shock on dobutamine has inadequate response. They are on chronic metoprolol. What inotrope might work better?", o: ["Higher dose dobutamine", "Milrinone — works via PDE-3 inhibition independent of beta receptors", "Phenylephrine", "Dopamine at renal dose"], a: 1, r: "Dobutamine works via beta-1 receptors that are downregulated by chronic beta-blocker therapy. Milrinone inhibits PDE-3, increasing cAMP independently of beta receptors, making it effective even in beta-blocked patients.", s: "Cardiovascular" },
  { q: "What does the IABP specifically improve during diastole?", o: ["Reduces preload", "Augments coronary artery perfusion pressure", "Increases afterload", "Reduces heart rate"], a: 1, r: "IABP counterpulsation inflates during diastole, displacing blood proximally (augmenting coronary perfusion) and distally (augmenting systemic perfusion). During systole, deflation reduces afterload, easing ventricular ejection.", s: "Cardiovascular" },
  { q: "What nursing assessment best indicates end-organ perfusion in cardiogenic shock?", o: ["Blood pressure alone", "Hourly urine output, mental status, skin perfusion, and lactate clearance", "Heart rate only", "CVP reading alone"], a: 1, r: "End-organ perfusion assessment: urine output (kidneys), mental status (brain), skin perfusion (peripheral circulation), and lactate clearance (tissue oxygenation). BP alone does not confirm adequate end-organ perfusion.", s: "Cardiovascular" },
  { q: "A patient in cardiogenic shock has a CVP of 18 mmHg. What does this indicate?", o: ["Hypovolemia", "Right heart volume overload/congestion", "Normal venous pressure", "Dehydration"], a: 1, r: "Elevated CVP (normal 2-6 mmHg) indicates right heart volume overload and impaired forward flow. In cardiogenic shock, this reflects backup from left heart failure or concurrent RV dysfunction. Fluid administration is NOT indicated.", s: "Cardiovascular" },
  { q: "A nurse prioritizing four patients in the ICU should assess which FIRST?", o: ["Stable post-PCI patient with BP 122/78", "Cardiogenic shock patient whose norepinephrine drip just ran out", "HF patient requesting dinner tray", "Post-MI patient with stable telemetry asking for pain medication"], a: 1, r: "Vasopressor interruption in cardiogenic shock is immediately life-threatening — the patient may decompensate rapidly. This requires immediate intervention to maintain hemodynamic support. Other situations are not immediately life-threatening.", s: "Cardiovascular" },
  { q: "Which intervention can be delegated to an LPN for a patient in cardiogenic shock?", o: ["Titrating vasopressor drips", "Monitoring hourly urine output measurement", "Performing initial shock assessment", "Managing IABP settings"], a: 1, r: "Measuring and recording hourly urine output is within LPN scope for stable procedures. Vasopressor titration, initial assessment, and IABP management require RN or critical care nurse expertise.", s: "Cardiovascular" },
  { q: "What is the primary goal of vasopressor therapy in cardiogenic shock?", o: ["Cure the underlying cause", "Maintain MAP ≥65 mmHg to ensure adequate end-organ perfusion while the cause is treated", "Reduce heart rate", "Increase urine output directly"], a: 1, r: "Vasopressors maintain MAP ≥65 mmHg as a bridge while the underlying cause is treated (e.g., emergent PCI for MI). They do not cure shock — they buy time for definitive treatment.", s: "Cardiovascular" },
  { q: "The oxygen supply-demand mismatch spiral in cardiogenic shock refers to:", o: ["Improving oxygen delivery", "Compensatory tachycardia increasing O2 demand while decreased coronary perfusion reduces O2 supply, worsening ischemia", "Stable oxygen balance", "Oxygen toxicity"], a: 1, r: "The vicious cycle: low CO → compensatory tachycardia and vasoconstriction (increased O2 demand) + decreased coronary perfusion (decreased O2 supply) → more ischemia → lower CO. Breaking this cycle requires revascularization and hemodynamic support.", s: "Cardiovascular" },
  { q: "What is the Impella device?", o: ["An external defibrillator", "A percutaneous microaxial pump placed across the aortic valve that directly unloads the left ventricle", "A type of pacemaker", "An IV medication"], a: 1, r: "The Impella is a catheter-based pump inserted percutaneously. It sits across the aortic valve, aspirating blood from the LV and ejecting it into the aorta, directly supporting cardiac output and reducing LV workload.", s: "Cardiovascular" },
  { q: "What type of ECMO is used for cardiogenic shock?", o: ["VV-ECMO (veno-venous)", "VA-ECMO (veno-arterial)", "High-flow nasal cannula", "CPAP"], a: 1, r: "VA-ECMO (veno-arterial) provides both cardiac and respiratory support: blood is drained from a vein, oxygenated externally, and returned to an artery, bypassing both the heart and lungs. VV-ECMO provides only respiratory support.", s: "Cardiovascular" },
  { q: "Acute mitral regurgitation from papillary muscle rupture in cardiogenic shock presents with:", o: ["Diastolic murmur", "New harsh systolic murmur at the apex radiating to the axilla", "No murmur", "Continuous machinery murmur"], a: 1, r: "Papillary muscle rupture causes acute severe mitral regurgitation with a new harsh systolic murmur best heard at the apex, radiating to the axilla or back. Unlike chronic MR, acute MR causes sudden hemodynamic collapse.", s: "Cardiovascular" },
  { q: "What is the role of serial lactate trending in cardiogenic shock management?", o: ["No role in shock management", "Guides resuscitation adequacy — lactate clearance >10% in 2 hours indicates improving perfusion", "Only useful at admission", "Replaced by BNP monitoring"], a: 1, r: "Serial lactate trending is more useful than single values: lactate clearance >10% per 2 hours indicates improving tissue perfusion and guides treatment response. Persistent or rising lactate despite treatment indicates inadequate resuscitation.", s: "Cardiovascular" },

  // ===== AAA (Questions 161-200) =====
  { q: "A 72-year-old male smoker presents with sudden severe tearing back pain, BP 76/42, and pulsatile abdominal mass. What is the priority nursing action?", o: ["Obtain CT scan", "Establish two large-bore IVs and prepare for emergent surgery", "Administer morphine", "Position in Trendelenburg"], a: 1, r: "Classic ruptured AAA presentation. Priority: large-bore IV access for resuscitation and emergent surgical notification. CT delays life-saving surgery in an unstable patient. Pain management is secondary to hemodynamic stabilization.", s: "Cardiovascular" },
  { q: "At what diameter does an abdominal aorta qualify as an aneurysm?", o: ["≥2 cm", "≥3 cm", "≥4 cm", "≥5 cm"], a: 1, r: "An AAA is defined as aortic diameter ≥3 cm (normal is approximately 2 cm). This represents a 50% increase above normal diameter.", s: "Cardiovascular" },
  { q: "What is the single strongest modifiable risk factor for AAA?", o: ["Hypertension", "Diabetes", "Tobacco use", "Obesity"], a: 2, r: "Tobacco use is the strongest modifiable risk factor: 90% of AAA patients are current/former smokers. Smoking promotes MMP activation, elastin degradation, and endothelial damage. Cessation slows growth by 20-30%.", s: "Cardiovascular" },
  { q: "Laplace's Law explains AAA rupture risk. What happens as aneurysm diameter increases?", o: ["Wall tension decreases", "Wall tension increases exponentially while the wall gets thinner", "The aneurysm becomes more stable", "Pressure decreases"], a: 1, r: "Wall tension = (P × r) / (2t). As radius increases, wall tension rises. Simultaneously, the wall thins (denominator decreases). Both changes increase tension exponentially — creating a positive feedback loop toward rupture.", s: "Cardiovascular" },
  { q: "Select ALL criteria for elective AAA repair.", o: ["Diameter ≥5.5 cm in men", "Diameter ≥5.0 cm in women", "Growth rate >0.5 cm in 6 months", "Any aneurysm regardless of size", "Symptomatic aneurysm of any size"], t: "sata", ca: [0, 1, 2, 4], r: "Repair indications: ≥5.5 cm (men), ≥5.0 cm (women), rapid growth >0.5 cm/6 months, or symptomatic at any size. Small asymptomatic aneurysms are managed with surveillance.", s: "Cardiovascular" },
  { q: "Select ALL appropriate nursing actions for suspected ruptured AAA.", o: ["Establish two large-bore IVs", "Type and crossmatch for massive transfusion", "Notify surgical team STAT", "Obtain CT scan before IV access", "Monitor vital signs every 15 minutes"], t: "sata", ca: [0, 1, 2, 4], r: "Ruptured AAA: IV access is the first priority, followed by blood preparation and surgical notification. CT should NOT delay IV access or surgical consult in an unstable patient.", s: "Cardiovascular" },
  { q: "Select ALL components of the massive transfusion protocol.", o: ["1:1:1 ratio PRBCs:FFP:Platelets", "Calcium supplementation", "Temperature management to prevent hypothermia", "Dextrose in water only", "Serial coagulation monitoring"], t: "sata", ca: [0, 1, 2, 4], r: "Massive transfusion: 1:1:1 ratio, calcium replacement (citrate in blood products chelates calcium), prevent hypothermia (blood warmer), and monitor coagulation. D5W alone is inappropriate for hemorrhagic resuscitation.", s: "Cardiovascular" },
  { q: "Permissive hypotension in ruptured AAA targets what SBP range?", o: ["120-140 mmHg", "100-120 mmHg", "70-90 mmHg", ">180 mmHg"], a: 2, r: "SBP target 70-90 mmHg prevents disrupting the retroperitoneal clot that may be tamponading the hemorrhage. Aggressive resuscitation to normal BP can displace this clot, worsening uncontrolled hemorrhage.", s: "Cardiovascular" },
  { q: "Which imaging is the gold standard for AAA surgical planning?", o: ["Abdominal X-ray", "CT angiography", "MRI", "Ultrasound"], a: 1, r: "CT angiography provides detailed assessment of aneurysm size, morphology, extent, relationship to renal arteries, and suitability for EVAR vs open repair. Ultrasound is used for screening and surveillance.", s: "Cardiovascular" },
  { q: "What screening recommendation does USPSTF make for AAA?", o: ["Screen all adults over 40", "One-time abdominal ultrasound for males 65-75 who have ever smoked", "Screen only symptomatic patients", "Annual CT for all elderly"], a: 1, r: "USPSTF Grade B recommendation: one-time screening abdominal ultrasound for males aged 65-75 who have ever smoked. This population has the highest prevalence of AAA.", s: "Cardiovascular" },
  { q: "Post-EVAR, the nurse monitors for what graft-specific complication?", o: ["Wound infection", "Endoleak — persistent blood flow into the aneurysm sac", "Urinary retention", "Constipation"], a: 1, r: "Endoleak is persistent blood flow into the aneurysm sac outside the graft. Types I and III require intervention; Type II may be observed. This is why lifelong surveillance imaging is required after EVAR.", s: "Cardiovascular" },
  { q: "A nurse is caring for four vascular patients. Which should be assessed FIRST?", o: ["Stable AAA patient with 4.2 cm aneurysm for scheduled ultrasound", "Postop EVAR patient with absent right pedal pulse and cold foot", "PAD patient with ABI 0.6 requesting wound care supplies", "AAA patient with BP 128/78 asking about smoking cessation"], a: 1, r: "Absent pedal pulse with cold foot post-EVAR suggests acute limb ischemia from graft limb occlusion or embolization — a surgical emergency requiring immediate assessment and intervention.", s: "Cardiovascular" },
  { q: "What type of aneurysm is most common in the abdominal aorta?", o: ["Saccular", "Fusiform (circumferential dilation)", "Dissecting", "Mycotic"], a: 1, r: "Fusiform aneurysms (circumferential, symmetric dilation involving the entire vessel circumference) are the most common AAA morphology. Saccular (outpouching) and mycotic (infectious) are less common.", s: "Cardiovascular" },
  { q: "Which complication of open AAA repair is caused by aortic cross-clamping?", o: ["Pneumonia", "Distal ischemia — renal failure, spinal cord ischemia, mesenteric ischemia", "Deep vein thrombosis", "Urinary retention"], a: 1, r: "Aortic cross-clamping causes temporary cessation of blood flow below the clamp. Organs at risk: kidneys (ATN), spinal cord (paraplegia), and mesenteric organs (ischemic bowel). Monitor UO, neurological function, and abdominal exam postoperatively.", s: "Cardiovascular" },
  { q: "What is the nurse's role in AAA surveillance for a patient with a 4.8 cm aneurysm?", o: ["No surveillance needed", "Educate about imaging schedule (every 6-12 months), BP control, and symptom recognition", "Immediate surgical referral", "Discharge with no follow-up"], a: 1, r: "4.8 cm AAA requires regular surveillance (imaging every 6-12 months), strict BP control (<120 systolic), smoking cessation, and education about warning symptoms requiring emergency care.", s: "Cardiovascular" },
  { q: "What blood pressure target reduces aortic wall stress in stable AAA?", o: ["SBP <160", "SBP <120 with beta-blocker preferred", "SBP <180", "No target needed"], a: 1, r: "SBP <120 mmHg reduces aortic wall shear stress (Laplace's Law). Beta-blockers are preferred because they also reduce the rate of pressure rise (dp/dt) on the aortic wall, potentially slowing aneurysm growth.", s: "Cardiovascular" },
  { q: "Grey Turner sign and Cullen sign indicate what in the context of AAA?", o: ["Cardiac ischemia", "Retroperitoneal hemorrhage — flank ecchymosis (Grey Turner) and periumbilical ecchymosis (Cullen)", "Pulmonary embolism", "Liver failure"], a: 1, r: "These are late signs of retroperitoneal hemorrhage: blood tracking to subcutaneous tissues causes flank discoloration (Grey Turner) and periumbilical discoloration (Cullen). Their absence does NOT rule out rupture.", s: "Cardiovascular" },
  { q: "EVAR has what advantage over open surgical repair?", o: ["No follow-up needed", "Less invasive (percutaneous), shorter recovery, lower perioperative mortality", "Eliminates the aneurysm entirely", "No graft complications possible"], a: 1, r: "EVAR advantages: minimally invasive (femoral access), shorter ICU/hospital stay, faster recovery, and lower 30-day mortality. Disadvantages: endoleak risk, requires specific anatomy, and lifelong imaging surveillance.", s: "Cardiovascular" },
  { q: "A patient with known 5.2 cm AAA develops sudden severe abdominal pain but remains hemodynamically stable. What should the nurse suspect?", o: ["Gastroenteritis", "Symptomatic (possibly expanding or contained rupture) AAA requiring urgent evaluation", "Constipation", "Urinary retention"], a: 1, r: "Sudden pain in a patient with known AAA of nearly surgical threshold suggests impending or contained rupture. Even if hemodynamically stable, this requires urgent surgical evaluation and preparation for possible emergent repair.", s: "Cardiovascular" },
  { q: "What education should a post-EVAR patient receive about long-term follow-up?", o: ["No follow-up needed after discharge", "Lifelong imaging surveillance for endoleak, graft migration, and continued aneurysm growth", "Only follow up if symptoms occur", "Annual blood tests only"], a: 1, r: "Post-EVAR requires lifelong surveillance: CT angiography or ultrasound at 1, 6, and 12 months, then annually. Monitor for endoleak, graft migration, limb occlusion, and continued sac expansion.", s: "Cardiovascular" },

  // ===== ISCHEMIC STROKE (Questions 201-240) =====
  { q: "A patient presents with right-sided weakness and expressive aphasia. Onset was 2 hours ago. CT shows no hemorrhage. BP is 178/96. What is the priority?", o: ["Lower BP to <140/90", "Administer IV alteplase", "Obtain MRI", "Give aspirin 325 mg immediately"], a: 1, r: "Within 4.5-hour window, no hemorrhage on CT, BP <185/110 → IV alteplase is the priority. BP 178/96 is below the threshold. Aspirin is held 24 hours post-tPA. MRI delays treatment.", s: "Neurological" },
  { q: "What is the tPA dose for ischemic stroke?", o: ["0.5 mg/kg", "0.9 mg/kg max 90 mg, 10% bolus then 90% over 60 minutes", "1.5 mg/kg", "Fixed 100 mg"], a: 1, r: "Stroke tPA dose: 0.9 mg/kg (max 90 mg). 10% given as IV bolus over 1 minute, remaining 90% infused over 60 minutes. Different from cardiac dose. Door-to-needle goal: <60 minutes.", s: "Neurological" },
  { q: "Which assessment is MOST critical before giving oral medications to a stroke patient?", o: ["Blood pressure", "Swallow screen", "Blood glucose", "Neurological exam"], a: 1, r: "Swallow screen must be passed before ANY oral intake (food, fluids, oral medications). Dysphagia is common post-stroke, and aspiration pneumonia is a leading cause of post-stroke morbidity and mortality.", s: "Neurological" },
  { q: "Select ALL contraindications for IV alteplase in ischemic stroke.", o: ["Active internal bleeding", "Blood glucose <50 mg/dL", "BP >185/110 despite treatment", "Prior intracranial hemorrhage", "Symptom onset >4.5 hours"], t: "sata", ca: [0, 1, 2, 3, 4], r: "All listed are contraindications. Active bleeding, hypoglycemia (mimics stroke), uncontrolled HTN, prior ICH, and time beyond the 4.5-hour window all preclude tPA administration.", s: "Neurological" },
  { q: "Select ALL appropriate post-tPA nursing interventions.", o: ["Neurological checks every 15 min × 2 hr", "Strict BP monitoring <180/105", "No antiplatelets for 24 hours", "Encourage immediate ambulation", "Monitor for hemorrhagic conversion"], t: "sata", ca: [0, 1, 2, 4], r: "Post-tPA: frequent neuro checks, strict BP <180/105, hold antiplatelets/anticoagulants × 24 hours, and monitor for hemorrhagic conversion. Immediate ambulation is contraindicated.", s: "Neurological" },
  { q: "Select ALL findings suggestive of hemorrhagic conversion post-tPA.", o: ["Sudden severe headache", "Vomiting", "New or worsening neurological deficit", "Improved speech", "Decreasing level of consciousness"], t: "sata", ca: [0, 1, 2, 4], r: "Hemorrhagic conversion signs: sudden headache, vomiting, worsening neuro deficit, and decreasing LOC. Any of these requires immediate tPA cessation and stat CT head. Improved speech is a positive finding.", s: "Neurological" },
  { q: "A nurse prioritizes four stroke patients. Which should be assessed FIRST?", o: ["Stroke patient 24 hours post-tPA with stable neuro exam", "Stroke patient 2 hours post-tPA with sudden severe headache and vomiting", "TIA patient with resolved symptoms awaiting workup", "Stroke patient ambulating with physical therapy"], a: 1, r: "Sudden headache and vomiting 2 hours post-tPA strongly suggest hemorrhagic conversion — a life-threatening emergency. Stop tPA immediately, obtain stat CT, and prepare for emergency intervention.", s: "Neurological" },
  { q: "Which task can a UAP perform for a stroke patient?", o: ["Perform swallow screen", "Administer aspirin", "Assist with positioning and turn patient", "Assess neurological status"], a: 2, r: "UAPs can assist with positioning and turning. Swallow screening, medication administration, and neurological assessment require nursing licensure and clinical judgment.", s: "Neurological" },
  { q: "Why must blood glucose be checked immediately in a patient presenting with stroke symptoms?", o: ["To determine diabetes status", "Hypoglycemia can mimic stroke and is a tPA contraindication", "It is routine only", "To calculate medication dose"], a: 1, r: "Hypoglycemia (<50 mg/dL) can perfectly mimic stroke (hemiparesis, aphasia, confusion). It is rapidly treatable with glucose and is a contraindication to tPA. Always check glucose before considering thrombolysis.", s: "Neurological" },
  { q: "The DAWN and DEFUSE-3 trials extended the thrombectomy window to:", o: ["6 hours", "12 hours", "24 hours in selected patients with favorable perfusion imaging", "48 hours"], a: 2, r: "These landmark trials showed that mechanical thrombectomy for LVO can be performed up to 24 hours if CT perfusion demonstrates large penumbra with small infarct core (mismatch), dramatically expanding the treatment window.", s: "Neurological" },
  { q: "What determines whether permissive hypertension is allowed in ischemic stroke?", o: ["Patient age", "Whether tPA is administered — if no tPA, allow up to 220/120", "Time of day", "Hospital policy only"], a: 1, r: "If tPA is given: BP must be <185/110 pre-tPA, <180/105 post-tPA. If no tPA: allow permissive HTN up to 220/120 to maintain perfusion to the ischemic penumbra through impaired autoregulation.", s: "Neurological" },
  { q: "An ACA (anterior cerebral artery) stroke causes which characteristic deficit?", o: ["Arm weakness > leg", "Contralateral leg weakness > arm", "Bilateral blindness", "Aphasia"], a: 1, r: "ACA supplies the medial cortical surface (leg motor/sensory area). ACA stroke causes contralateral leg weakness > arm, personality changes, and urinary incontinence. This contrasts with MCA stroke (arm/face > leg).", s: "Neurological" },
  { q: "What is the most common cause of cardioembolic stroke?", o: ["Mitral valve prolapse", "Atrial fibrillation", "Patent foramen ovale", "Ventricular septal defect"], a: 1, r: "AF is the most common cause of cardioembolic stroke (5-fold increased risk). Stagnant blood flow in the fibrillating left atrial appendage promotes thrombus formation that can embolize to the brain.", s: "Neurological" },
  { q: "What is the therapeutic window for IV alteplase in ischemic stroke?", o: ["2 hours", "3 hours", "4.5 hours from last known well time", "8 hours"], a: 2, r: "IV alteplase window: 4.5 hours from last known well time. 'Last known well' (not symptom onset) determines eligibility. If a patient wakes with symptoms, the time is counted from when they were last observed neurologically intact.", s: "Neurological" },
  { q: "What is the significance of the NIHSS score in stroke management?", o: ["It determines medication doses", "It standardizes stroke severity assessment and guides treatment decisions", "It measures blood flow", "It predicts heart attack risk"], a: 1, r: "NIHSS (0-42) standardizes stroke severity: guides tPA eligibility (higher scores may benefit more), thrombectomy selection (NIHSS ≥6 suggests LVO), and predicts outcomes. Serial NIHSS trending monitors for improvement or deterioration.", s: "Neurological" },
  { q: "What type of stroke is most likely if symptoms affect multiple vascular territories simultaneously?", o: ["Thrombotic stroke", "Embolic stroke", "Lacunar stroke", "Hemorrhagic stroke"], a: 1, r: "Embolic strokes can affect multiple vascular territories because emboli from the heart or proximal arteries can lodge in different cerebral arteries. Thrombotic strokes develop in situ at one location.", s: "Neurological" },
  { q: "What post-stroke complication is prevented by the swallow screen?", o: ["DVT", "Aspiration pneumonia", "Pressure ulcer", "UTI"], a: 1, r: "The swallow screen prevents aspiration pneumonia, a leading cause of post-stroke morbidity and mortality. Dysphagia from cranial nerve dysfunction makes patients at high risk for aspirating food, fluids, and oral secretions.", s: "Neurological" },
  { q: "What head position is recommended for acute ischemic stroke?", o: ["HOB 30 degrees", "HOB flat to maximize cerebral perfusion", "Trendelenburg", "Prone"], a: 1, r: "HOB flat maximizes cerebral blood flow through gravity-assisted perfusion. Important when autoregulation is impaired. Exception: elevate HOB if significant cerebral edema, aspiration risk, or increased ICP.", s: "Neurological" },
  { q: "A patient had a TIA that resolved completely after 45 minutes. Is this an emergency?", o: ["No — symptoms resolved so no treatment needed", "Yes — TIA is a medical emergency because 10-15% of patients have a stroke within 90 days", "Only if it lasted >24 hours", "Only in elderly patients"], a: 1, r: "TIA is a medical emergency. 10-15% of TIA patients have a stroke within 90 days, with highest risk in the first 48 hours. Urgent workup (imaging, cardiac monitoring, risk factor assessment) and treatment are essential.", s: "Neurological" },
  { q: "What medication is given for secondary stroke prevention in atrial fibrillation?", o: ["Aspirin alone", "Anticoagulation (warfarin or DOAC)", "Clopidogrel alone", "Statin only"], a: 1, r: "AF-related cardioembolic stroke requires anticoagulation (not just antiplatelet). DOACs (apixaban, rivarfaxaban, dabigatran, edoxaban) are preferred over warfarin for non-valvular AF due to lower bleeding risk and no INR monitoring.", s: "Neurological" },

  // ===== HEMORRHAGIC STROKE (Questions 241-280) =====
  { q: "A patient presents with sudden thunderclap headache, nuchal rigidity, and photophobia. CT head is positive for subarachnoid blood. What is the diagnosis?", o: ["Migraine", "Subarachnoid hemorrhage", "Tension headache", "Meningitis"], a: 1, r: "Sudden thunderclap headache + meningeal signs (nuchal rigidity, photophobia) + blood on CT = SAH. Most commonly from ruptured cerebral aneurysm. This is a neurosurgical emergency.", s: "Neurological" },
  { q: "What is the BP target for acute ICH within the first hour?", o: ["SBP <180", "SBP <140", "SBP <120", "No target"], a: 1, r: "Per INTERACT2/ATACH-2 trials, rapid SBP reduction to <140 mmHg within 1 hour reduces hematoma expansion and improves outcomes. IV nicardipine or clevidipine provide smooth, titratable control.", s: "Neurological" },
  { q: "Nimodipine dosing for SAH vasospasm prevention is:", o: ["30 mg IV every 6 hours", "60 mg PO/NG every 4 hours × 21 days", "120 mg PO daily", "10 mg IV once"], a: 1, r: "Nimodipine 60 mg PO/NG every 4 hours × 21 days. NEVER give IV (fatal cardiovascular collapse). Must be given ON TIME — missed doses increase vasospasm risk. Reduce to 30 mg if hypotensive.", s: "Neurological" },
  { q: "Select ALL signs of cerebral vasospasm in a post-SAH patient (days 4-14).", o: ["New focal neurological deficit", "Confusion or decreased LOC", "Increased velocities on transcranial Doppler", "Improved headache", "Fever"], t: "sata", ca: [0, 1, 2], r: "Vasospasm causes delayed cerebral ischemia: new focal deficits, confusion, decreased LOC, and increased TCD velocities (narrowed vessels). Improved headache is not a vasospasm sign. Fever has multiple causes.", s: "Neurological" },
  { q: "Select ALL components of aneurysm precautions.", o: ["Dim, quiet environment", "Stool softeners to prevent Valsalva", "Limit visitors", "Bed rest", "Encourage vigorous activity"], t: "sata", ca: [0, 1, 2, 3], r: "Aneurysm precautions minimize stimulation and ICP spikes to prevent rebleeding: dim room, stool softeners (no straining), limited visitors, bed rest, anxiolytics PRN. Vigorous activity is contraindicated.", s: "Neurological" },
  { q: "Select ALL appropriate interventions for acute ICH.", o: ["IV alteplase", "Rapid BP reduction to SBP <140", "Reverse anticoagulation if applicable", "Seizure prophylaxis if seizures occur", "HOB 30 degrees"], t: "sata", ca: [1, 2, 3, 4], r: "ICH management: rapid BP control, anticoagulation reversal, seizure treatment, HOB elevation 30°. IV tPA is absolutely contraindicated in hemorrhagic stroke (would worsen bleeding).", s: "Neurological" },
  { q: "A nurse is prioritizing four neuro patients. Which should be assessed FIRST?", o: ["SAH patient day 10 with stable neuro exam", "SAH patient day 7 with new left arm weakness and confusion", "ICH patient post-craniotomy day 3 with stable vitals", "Stroke patient in rehab making progress"], a: 1, r: "New focal deficit on day 7 post-SAH (within vasospasm window days 4-14) strongly suggests delayed cerebral ischemia from vasospasm. Immediate evaluation and treatment are required.", s: "Neurological" },
  { q: "What is the antidote for warfarin-associated ICH?", o: ["Protamine sulfate", "4-factor PCC (Kcentra) + IV vitamin K", "Aminocaproic acid", "Fresh frozen plasma alone"], a: 1, r: "4-factor PCC provides rapid reversal within 10-15 minutes (contains factors II, VII, IX, X). Given WITH IV vitamin K 10 mg (PCC is temporary, vitamin K provides sustained reversal). FFP is slower and causes volume overload.", s: "Neurological" },
  { q: "HOB positioning for hemorrhagic stroke should be:", o: ["Flat to maximize perfusion", "30 degrees elevated, head midline to promote venous drainage and reduce ICP", "Trendelenburg", "Does not matter"], a: 1, r: "HOB 30° promotes cerebral venous drainage through the jugular veins, reducing ICP. Head midline prevents jugular vein compression. Avoid neck flexion and Valsalva maneuvers.", s: "Neurological" },
  { q: "Cerebral salt wasting and SIADH both cause hyponatremia in SAH. How are they distinguished?", o: ["They are identical", "CSW = hypovolemic (treat with NS); SIADH = euvolemic/hypervolemic (treat with fluid restriction)", "By sodium level only", "By age of patient"], a: 1, r: "Volume status differentiates: CSW causes sodium wasting with volume depletion (treat with NS repletion). SIADH causes water retention with euvolemia/hypervolemia (treat with fluid restriction). Incorrect treatment can be fatal.", s: "Neurological" },
  { q: "What grading system is used to classify SAH severity?", o: ["Glasgow Coma Scale only", "Hunt-Hess scale (I-V) based on clinical symptoms", "NIHSS only", "ICH Score"], a: 1, r: "Hunt-Hess scale: I = asymptomatic/mild HA, II = severe HA/nuchal rigidity, III = drowsy/mild deficit, IV = stupor/hemiparesis, V = coma/posturing. Higher grade = worse prognosis. Guides treatment aggressiveness and prognosis discussions.", s: "Neurological" },
  { q: "What is the rebleeding risk in the first 24 hours after SAH without aneurysm securing?", o: ["<1%", "4%", "15%", "50%"], a: 1, r: "The rebleeding risk is 4% on day 1, then ~1.5%/day for 14 days without treatment. Rebleeding carries 70% mortality. This is why definitive aneurysm securing (clipping or coiling) is performed urgently, ideally within 24 hours.", s: "Neurological" },
  { q: "Which cranial nerve is compressed in uncal herniation, causing a fixed dilated pupil?", o: ["CN II (optic)", "CN III (oculomotor)", "CN VI (abducens)", "CN VII (facial)"], a: 1, r: "CN III (oculomotor nerve) is compressed as the uncus of the temporal lobe herniates through the tentorial notch. This causes ipsilateral pupil dilation (mydriasis) and loss of the light reflex — an ominous sign of herniation.", s: "Neurological" },
  { q: "What EVD complication should the nurse monitor for?", o: ["Only mechanical failure", "Infection (ventriculitis), overdrainage, hemorrhage, and malposition", "No complications occur with EVDs", "Only headache"], a: 1, r: "EVD complications: ventriculitis/infection (maintain strict aseptic technique), overdrainage (headache, collapse), hemorrhage, and malposition. Monitor CSF color/clarity, volume, ICP readings, and insertion site.", s: "Neurological" },
  { q: "What percentage of strokes are hemorrhagic, and what proportion of stroke deaths do they cause?", o: ["50% of strokes, 50% of deaths", "13% of strokes but 30-50% of stroke deaths", "5% of strokes and 5% of deaths", "90% of strokes"], a: 1, r: "Hemorrhagic strokes account for only ~13% of all strokes but cause 30-50% of stroke-related deaths, making them disproportionately lethal compared to ischemic strokes.", s: "Neurological" },
  { q: "What causes Charcot-Bouchard microaneurysms?", o: ["Congenital defect", "Chronic hypertension causing lipohyalinosis of small perforating arteries", "Atherosclerosis of large arteries", "Infection"], a: 1, r: "Sustained hypertension causes fibrinoid necrosis (lipohyalinosis) of small perforating arteries, weakening their walls and forming Charcot-Bouchard microaneurysms. When these rupture, they cause hypertensive ICH, typically in the basal ganglia.", s: "Neurological" },
  { q: "What is the most common cause of non-traumatic SAH?", o: ["AVM rupture", "Ruptured cerebral (berry) aneurysm (80%)", "Hypertension", "Cocaine use"], a: 1, r: "Ruptured cerebral aneurysm accounts for ~80% of non-traumatic SAH. These berry aneurysms form at arterial bifurcation points in the Circle of Willis where hemodynamic stress weakens the vessel wall.", s: "Neurological" },
  { q: "A CT head is negative for SAH but clinical suspicion remains high. What is the next step?", o: ["Discharge home", "Lumbar puncture to assess for xanthochromia", "MRI brain", "Repeat CT in 1 week"], a: 1, r: "CT sensitivity for SAH decreases over time (98% at 12 hours → 50% at 1 week). Negative CT with high clinical suspicion requires LP: xanthochromia (yellowish CSF from bilirubin) confirms SAH even when CT is negative.", s: "Neurological" },
  { q: "Nicardipine IV is preferred for BP management in ICH because:", o: ["It is the cheapest", "Smooth, predictable, titratable BP reduction through calcium channel blockade", "It reverses anticoagulation", "It prevents seizures"], a: 1, r: "Nicardipine provides smooth arterial vasodilation through L-type calcium channel blockade, allowing precise BP titration. Start 5 mg/hr, increase by 2.5 mg/hr every 5-15 min (max 15 mg/hr). Target SBP <140 within 1 hour.", s: "Neurological" },
  { q: "What defines the ICH Score and what does it predict?", o: ["Stroke rehabilitation potential", "30-day mortality based on GCS, ICH volume, IVH presence, infratentorial location, and age >80", "Treatment eligibility for tPA", "Long-term cognitive outcome"], a: 1, r: "ICH Score (0-6 points): GCS (0-2), ICH volume ≥30 mL (1), IVH (1), infratentorial origin (1), age >80 (1). Higher scores predict higher 30-day mortality: 0 = 0%, 1 = 13%, 2 = 26%, 3 = 72%, 4 = 97%, 5-6 = ~100%.", s: "Neurological" },

  // ===== SEIZURES (Questions 281-320) =====
  { q: "A patient is having a generalized tonic-clonic seizure. What is the nurse's FIRST action?", o: ["Restrain the patient to prevent injury", "Insert a padded tongue blade", "Turn to the side, protect the head, time the seizure", "Administer oral lorazepam"], a: 2, r: "Priority: protect from injury (turn to side for airway, cushion head), time the seizure, and observe characteristics. NEVER restrain (fracture risk), insert anything in mouth (aspiration risk), or give oral meds during active seizure.", s: "Neurological" },
  { q: "Status epilepticus is treated with which first-line medication?", o: ["Phenytoin IV", "Lorazepam 0.1 mg/kg IV", "Valproic acid", "Carbamazepine"], a: 1, r: "Lorazepam is first-line for SE: 0.1 mg/kg IV (max 4 mg). Fastest onset and longest brain duration among benzodiazepines. Repeat once at 5 minutes if seizure continues. Have airway equipment ready.", s: "Neurological" },
  { q: "A patient on phenytoin has a drug level of 24 mcg/mL (therapeutic 10-20). What sign should the nurse expect?", o: ["Improved seizure control", "Nystagmus and ataxia (earliest signs of toxicity)", "No symptoms", "Hypotension"], a: 1, r: "Nystagmus is the first sign of phenytoin toxicity (typically at levels >20), followed by ataxia, slurred speech, and lethargy at higher levels. Due to zero-order kinetics, levels can rise disproportionately with small dose changes.", s: "Neurological" },
  { q: "Select ALL appropriate seizure precautions for hospitalized patients.", o: ["Padded side rails", "Suction at bedside", "Oxygen readily available", "Bed in lowest position", "Tongue blade taped to head of bed for insertion during seizure"], t: "sata", ca: [0, 1, 2, 3], r: "Seizure precautions: padded rails, suction, oxygen, low bed position. Tongue blades should NOT be inserted during seizures (aspiration risk, broken teeth). They may be available at bedside but never used during active seizure.", s: "Neurological" },
  { q: "Select ALL correct statements about phenytoin administration.", o: ["Mix only with normal saline (never dextrose)", "Zero-order kinetics cause disproportionate level increases", "Gingival hyperplasia is a common side effect", "Give rapidly to ensure therapeutic levels", "Teratogenic — causes fetal hydantoin syndrome"], t: "sata", ca: [0, 1, 2, 4], r: "Phenytoin: NS only (precipitates in dextrose), zero-order kinetics, gingival hyperplasia, and teratogenicity. Administer slowly (max 50 mg/min for phenytoin, 150 mg PE/min for fosphenytoin) to prevent cardiovascular toxicity.", s: "Neurological" },
  { q: "Select ALL common triggers for breakthrough seizures.", o: ["Medication non-adherence", "Sleep deprivation", "Alcohol use", "High-protein diet", "Metabolic disturbances (hypoglycemia, hyponatremia)"], t: "sata", ca: [0, 1, 2, 4], r: "Common seizure triggers: medication non-adherence (most common), sleep deprivation, alcohol, flickering lights, stress, infection, and metabolic disturbances. High-protein diet is not a seizure trigger.", s: "Neurological" },
  { q: "A nurse is prioritizing four patients. Which should be assessed FIRST?", o: ["Epilepsy patient with phenytoin level 14 mcg/mL and mild headache", "Patient in continuous tonic-clonic seizure for 6 minutes", "Post-seizure patient sleeping comfortably", "Epilepsy patient asking about driving restrictions"], a: 1, r: "Continuous seizure >5 minutes = status epilepticus, a medical emergency. GABA receptor internalization and NMDA activation make SE progressively harder to treat. Immediate benzodiazepine is required.", s: "Neurological" },
  { q: "Which task can be delegated to a UAP for a seizure patient?", o: ["Administering lorazepam IV", "Staying with the patient and calling for help if seizure occurs", "Performing post-ictal neurological assessment", "Adjusting AED doses"], a: 1, r: "UAPs can stay with at-risk patients and activate the emergency response. Medication administration, neurological assessment, and medication adjustment require nursing licensure.", s: "Neurological" },
  { q: "What is the mechanism by which lorazepam stops seizures?", o: ["Blocks sodium channels", "Enhances GABA-A receptor chloride channel opening, hyperpolarizing neurons", "Blocks glutamate receptors", "Inhibits dopamine"], a: 1, r: "Benzodiazepines enhance GABA-A receptor activity by increasing the frequency of chloride channel opening. Chloride influx hyperpolarizes neurons, counteracting the excessive depolarization driving the seizure.", s: "Neurological" },
  { q: "Why should phenytoin never be abruptly discontinued?", o: ["It causes rebound hypertension", "Risk of rebound seizures and status epilepticus", "It has no withdrawal effects", "It must be tapered over 6 months"], a: 1, r: "Abrupt AED discontinuation can trigger rebound seizures and status epilepticus. The brain, adapted to the drug's anticonvulsant effect, becomes hyperexcitable without it. AEDs must be tapered gradually under medical supervision.", s: "Neurological" },
  { q: "What is Todd paralysis?", o: ["Permanent stroke-like paralysis", "Transient post-ictal focal weakness (resolves within 24-48 hours) following a seizure", "A medication side effect", "A type of seizure"], a: 1, r: "Todd paralysis is transient focal weakness following a seizure, typically resolving within 24-48 hours. It can mimic acute stroke. Key differentiator: follows a witnessed seizure and is transient.", s: "Neurological" },
  { q: "Valproic acid is contraindicated in which patient population?", o: ["Men over 60", "Women of childbearing age due to teratogenicity (neural tube defects)", "Children under 2 only", "Patients with hypertension"], a: 1, r: "Valproic acid is highly teratogenic (1-2% neural tube defect risk). Levetiracetam or lamotrigine are preferred for women of childbearing age. All women on AEDs need folic acid supplementation (4 mg/day pre-conception).", s: "Neurological" },
  { q: "What 'Keppra rage' refers to:", o: ["A rash from levetiracetam", "Behavioral changes including irritability, aggression, and mood disturbance", "Levetiracetam overdose", "An allergic reaction"], a: 1, r: "Levetiracetam can cause behavioral side effects (irritability, aggression, emotional lability) in some patients, especially in the first weeks. Monitor closely and report to provider for potential dose adjustment or medication change.", s: "Neurological" },
  { q: "What EEG pattern is diagnostic for seizures?", o: ["Flat line", "Epileptiform discharges (spikes, sharp waves, spike-wave complexes)", "Normal alpha rhythm", "Low-voltage activity"], a: 1, r: "Epileptiform discharges (spikes, sharp waves, spike-and-wave complexes) on EEG are the hallmark of seizure activity. Interictal discharges support epilepsy diagnosis even without capturing a clinical seizure.", s: "Neurological" },
  { q: "A patient with a seizure disorder is admitted for surgery. Their AED was held the morning of surgery. What concern should the nurse raise?", o: ["No concern — routine to hold medications pre-surgery", "Holding AEDs increases seizure risk, especially perioperatively. Administer via alternative route if NPO", "AEDs can always be safely held", "Only IV AEDs matter"], a: 1, r: "AEDs should NOT be held perioperatively due to seizure risk (stress, sleep deprivation, medication gaps are triggers). If NPO, administer via IV or NG route. Most AEDs have IV formulations or can be given via NG tube.", s: "Neurological" },
  { q: "What is the kindling phenomenon and its clinical significance?", o: ["A diagnostic test", "Repeated seizures lower the threshold for future seizures — supporting early aggressive treatment", "A type of epilepsy surgery", "A medication interaction"], a: 1, r: "Kindling: each seizure causes neuronal changes (synaptic reorganization, receptor alterations) that lower the seizure threshold, making future seizures more likely and severe. This 'seizures beget seizures' concept supports early, aggressive AED therapy.", s: "Neurological" },
  { q: "Rhabdomyolysis from prolonged tonic-clonic seizure presents with:", o: ["Clear urine", "Dark cola-colored urine, elevated CK, muscle pain", "Polyuria", "Hematuria only"], a: 1, r: "Prolonged tonic-clonic activity → skeletal muscle breakdown → myoglobin release → dark urine (myoglobinuria). Elevated CK confirms rhabdomyolysis. Aggressive IV hydration is needed to prevent acute kidney injury from myoglobin precipitation in renal tubules.", s: "Neurological" },
  { q: "What AED requires no therapeutic drug level monitoring?", o: ["Phenytoin", "Carbamazepine", "Levetiracetam", "Valproic acid"], a: 2, r: "Levetiracetam does not require drug level monitoring — one of its major advantages. It is renally cleared (minimal drug interactions), has IV/PO bioequivalence, and wide therapeutic range. Phenytoin, carbamazepine, and valproate all require level monitoring.", s: "Neurological" },
  { q: "What is the second-line treatment if lorazepam fails to stop status epilepticus?", o: ["More lorazepam indefinitely", "Fosphenytoin, levetiracetam, or valproate IV", "Oral carbamazepine", "Observation only"], a: 1, r: "SE treatment ladder: 1st-line = lorazepam. 2nd-line = fosphenytoin (20 mg PE/kg), levetiracetam (60 mg/kg), or valproate (40 mg/kg) IV. 3rd-line = continuous infusion (midazolam/propofol/pentobarbital) with EEG monitoring.", s: "Neurological" },
  { q: "What is the most common seizure type in children?", o: ["Generalized tonic-clonic", "Absence (petit mal) seizures", "Complex partial", "Myoclonic"], a: 1, r: "Absence seizures (brief 5-30 second staring spells with abrupt onset/offset, no post-ictal phase) are characteristic of childhood epilepsy. Often mistaken for inattention. First-line treatment: ethosuximide or valproate.", s: "Neurological" },

  // ===== MENINGITIS (Questions 321-360) =====
  { q: "A patient with suspected bacterial meningitis arrives in the ED. CT is pending. What is the FIRST nursing priority?", o: ["Wait for CT results", "Administer empiric IV antibiotics immediately", "Perform lumbar puncture first", "Apply airborne precautions"], a: 1, r: "Empiric antibiotics IMMEDIATELY — mortality increases ~30%/hour of delay. Do NOT delay for CT, LP, or any test. Blood cultures can be drawn simultaneously if possible, but antibiotics take priority.", s: "Neurological" },
  { q: "What is the empiric antibiotic regimen for community-acquired bacterial meningitis in adults?", o: ["Amoxicillin alone", "Ceftriaxone + vancomycin ± ampicillin (for Listeria if >50, immunocompromised, or alcoholic)", "Azithromycin", "Ciprofloxacin alone"], a: 1, r: "Ceftriaxone covers pneumococcus and meningococcus. Vancomycin covers penicillin-resistant pneumococcus. Ampicillin is added for Listeria coverage in at-risk populations (>50 years, immunocompromised, alcoholic).", s: "Neurological" },
  { q: "When must dexamethasone be given in bacterial meningitis?", o: ["After 24 hours of antibiotics", "15-20 minutes BEFORE or WITH the first antibiotic dose", "Only after cultures return", "Dexamethasone is not used"], a: 1, r: "Dexamethasone must be given before or with the first antibiotic dose to reduce the inflammatory surge from bacterial cell wall lysis. Starting after antibiotics provides no benefit. Reduces mortality and hearing loss in pneumococcal meningitis.", s: "Neurological" },
  { q: "Select ALL CSF findings consistent with bacterial meningitis.", o: ["Elevated WBC >1000/μL (neutrophils predominant)", "Decreased glucose (<40 mg/dL or CSF:serum ratio <0.4)", "Elevated protein (>45 mg/dL)", "Normal glucose", "Lymphocyte predominance"], t: "sata", ca: [0, 1, 2], r: "Bacterial meningitis CSF: neutrophilic pleocytosis (>1000 WBC), low glucose (bacteria and neutrophils consume it), high protein (BBB disruption). Lymphocyte predominance and normal glucose are seen in viral meningitis.", s: "Neurological" },
  { q: "Select ALL appropriate nursing interventions for suspected meningitis.", o: ["Prioritize antibiotic administration", "Implement droplet precautions", "Dim, quiet environment", "Monitor neurological status every 1-2 hours", "Encourage oral fluids before swallow assessment"], t: "sata", ca: [0, 1, 2, 3], r: "Priority: antibiotics immediately, droplet precautions (meningococcal), dim/quiet environment (photophobia/phonophobia), and frequent neuro checks. Do not give oral fluids before ensuring safe swallowing.", s: "Neurological" },
  { q: "Select ALL complications of bacterial meningitis.", o: ["Sensorineural hearing loss", "Seizures", "Hydrocephalus", "Improved cognition", "Cranial nerve palsies"], t: "sata", ca: [0, 1, 2, 4], r: "Meningitis complications: hearing loss (most common sequela, up to 30%), seizures (20-30%), hydrocephalus (from impaired CSF absorption), and cranial nerve palsies (from basal exudate). Cognition may worsen, not improve.", s: "Neurological" },
  { q: "A nurse is prioritizing four patients. Which should be assessed FIRST?", o: ["Known meningitis patient on antibiotics for 48 hours, improving", "Patient with fever, severe headache, and nuchal rigidity — meningitis suspected but not yet treated", "Post-LP patient with mild headache", "Meningitis patient asking about prophylaxis for family"], a: 1, r: "Suspected untreated meningitis is the highest priority — every hour of antibiotic delay increases mortality by ~30%. This patient needs immediate antibiotics, blood cultures, and evaluation.", s: "Neurological" },
  { q: "Which isolation precaution is required for suspected meningococcal meningitis?", o: ["Standard only", "Droplet precautions", "Airborne precautions", "Contact precautions"], a: 1, r: "Droplet precautions (surgical mask within 3 feet) until N. meningitidis is ruled out or patient has been on effective antibiotics for 24 hours. Meningococcus is transmitted via respiratory droplets, not airborne.", s: "Neurological" },
  { q: "What prophylaxis should close contacts of meningococcal disease receive?", o: ["No prophylaxis needed", "Ciprofloxacin 500 mg single dose OR rifampin 600 mg q12h × 2 days", "Full 14-day antibiotic course", "Vaccination only"], a: 1, r: "Close contacts (household members, daycare, direct secretion exposure) need chemoprophylaxis: ciprofloxacin single dose (adults) or rifampin × 2 days to eliminate nasopharyngeal carriage and prevent secondary cases.", s: "Neurological" },
  { q: "What physical exam finding is positive when neck flexion causes involuntary hip/knee flexion?", o: ["Kernig sign", "Brudzinski sign", "Babinski sign", "Romberg sign"], a: 1, r: "Brudzinski sign: passive neck flexion → involuntary hip/knee flexion (meningeal irritation). Kernig sign: with hip flexed 90°, resistance to knee extension. Both indicate meningeal irritation. Low sensitivity but high specificity.", s: "Neurological" },
  { q: "A petechial rash progressing to purpura in meningitis suggests which organism and complication?", o: ["S. pneumoniae with no complications", "N. meningitidis with DIC and risk for Waterhouse-Friderichsen syndrome", "Listeria with sepsis", "H. influenzae with edema"], a: 1, r: "Petechial/purpuric rash = meningococcemia with DIC. Can progress to Waterhouse-Friderichsen syndrome (bilateral adrenal hemorrhage → shock, DIC, adrenal crisis). Requires emergent antibiotics, fluids, and possibly steroids.", s: "Neurological" },
  { q: "Why is vancomycin infused slowly (≥60 minutes)?", o: ["To improve efficacy", "To prevent Red Man syndrome (histamine-mediated flushing from rapid infusion)", "No reason for slow infusion", "To reduce kidney damage"], a: 1, r: "Rapid vancomycin infusion triggers histamine release from mast cells → Red Man syndrome (flushing, erythema, pruritus of upper body). This is NOT a true allergy but a rate-dependent reaction prevented by slow infusion.", s: "Neurological" },
  { q: "What is the target vancomycin trough for meningitis?", o: ["5-10 mcg/mL", "10-15 mcg/mL", "15-20 mcg/mL", "25-30 mcg/mL"], a: 2, r: "Meningitis requires higher vancomycin troughs (15-20 mcg/mL) than standard infections because CSF penetration is limited even with inflamed meninges. Higher levels increase nephrotoxicity/ototoxicity risk — monitor closely.", s: "Neurological" },
  { q: "When is a CT scan indicated BEFORE lumbar puncture in suspected meningitis?", o: ["Always before LP", "Only if papilledema, focal deficits, altered consciousness, immunocompromised, or seizures are present", "Never needed before LP", "Only in children"], a: 1, r: "CT before LP is needed when there is risk of increased ICP or mass lesion (papilledema, focal deficits, altered LOC, immunocompromised, seizures). LP in presence of mass/herniation risk can be fatal. But NEVER delay antibiotics for CT.", s: "Neurological" },
  { q: "A patient with meningitis develops sodium of 128 mEq/L. What complication is most likely?", o: ["Dehydration", "SIADH causing dilutional hyponatremia", "Renal failure", "Hyperaldosteronism"], a: 1, r: "SIADH is a common meningitis complication: excessive ADH secretion → water retention → dilutional hyponatremia. Management: fluid restriction, monitor sodium, and correct slowly to prevent osmotic demyelination syndrome.", s: "Neurological" },
  { q: "What hearing complication must be screened for after bacterial meningitis?", o: ["Conductive hearing loss", "Sensorineural hearing loss — audiometry recommended before discharge", "Tinnitus only", "No hearing complications occur"], a: 1, r: "Sensorineural hearing loss is the most common permanent sequela (up to 30% in pneumococcal meningitis). Cochlear nerve and inner ear damage from inflammation. Audiometric testing recommended before discharge.", s: "Neurological" },
  { q: "Meningitis causes three types of cerebral edema. Which type results from impaired CSF absorption?", o: ["Vasogenic edema", "Cytotoxic edema", "Interstitial edema (from obstructed CSF flow and impaired absorption)", "No edema occurs"], a: 2, r: "Interstitial edema: inflamed arachnoid granulations cannot absorb CSF + purulent exudate blocks CSF pathways → hydrocephalus. Also vasogenic (BBB disruption) and cytotoxic (direct cellular damage). All increase ICP.", s: "Neurological" },
  { q: "What age groups require ampicillin in the empiric meningitis regimen?", o: ["All ages", "Neonates and adults >50 years, immunocompromised, or alcoholic", "Only children 5-10", "Only elderly >80"], a: 1, r: "Ampicillin covers Listeria monocytogenes in populations at risk: neonates (Group B strep also), adults >50, immunocompromised, and alcoholic patients. Cephalosporins do NOT cover Listeria.", s: "Neurological" },
  { q: "What is the significance of gram-positive diplococci on CSF gram stain?", o: ["Normal finding", "Streptococcus pneumoniae — the most common cause of bacterial meningitis in adults", "Contamination", "Viral meningitis"], a: 1, r: "Gram-positive diplococci = S. pneumoniae (pneumococcus), the most common cause of bacterial meningitis in adults. Gram stain is positive in 60-90% of bacterial meningitis cases and helps guide antibiotic selection.", s: "Neurological" },
  { q: "What environmental modifications benefit a meningitis patient?", o: ["Bright lights and stimulation", "Dim, quiet environment with minimal stimulation", "Cold room temperature", "Loud TV for comfort"], a: 1, r: "Meningeal inflammation causes severe photophobia and phonophobia. Dim lighting, quiet environment, minimal unnecessary stimulation, and limiting painful procedures reduce patient distress and ICP-aggravating stimuli.", s: "Neurological" },

  // ===== PARKINSON DISEASE (Questions 361-400) =====
  { q: "What are the cardinal motor features of Parkinson disease (TRAP)?", o: ["Tachycardia, Rash, Aphasia, Paralysis", "Tremor (resting), Rigidity, Akinesia/bradykinesia, Postural instability", "Tremor (intention), Rash, Agitation, Pain", "Tinnitus, Rigidity, Ataxia, Ptosis"], a: 1, r: "TRAP: resting tremor (pill-rolling, 4-6 Hz), rigidity (cogwheel), akinesia/bradykinesia (required for diagnosis), and postural instability. Motor symptoms appear after 60-80% of dopaminergic neurons are lost.", s: "Neurological" },
  { q: "Carbidopa-levodopa should be taken how in relation to meals?", o: ["With a high-protein meal", "30 minutes before or 1 hour after meals", "It doesn't matter", "Only at bedtime"], a: 1, r: "Dietary protein competes with levodopa for intestinal absorption and BBB transport via the large neutral amino acid transporter. Taking levodopa 30 min before or 1 hr after meals optimizes absorption and CNS delivery.", s: "Neurological" },
  { q: "What happens if carbidopa-levodopa is abruptly discontinued?", o: ["No effect", "Life-threatening parkinsonism-hyperpyrexia syndrome resembling NMS", "Immediate symptom improvement", "Mild tremor only"], a: 1, r: "Abrupt discontinuation causes severe rigidity, hyperthermia, altered consciousness, autonomic instability, and elevated CK — resembling NMS. This can be fatal. Levodopa must NEVER be stopped abruptly.", s: "Neurological" },
  { q: "Select ALL impulse control disorders associated with dopamine agonists.", o: ["Compulsive gambling", "Hypersexuality", "Compulsive shopping", "Binge eating", "Improved judgment"], t: "sata", ca: [0, 1, 2, 3], r: "Dopamine agonists (pramipexole, ropinirole) cause impulse control disorders in 15-20% of patients: gambling, hypersexuality, compulsive shopping, binge eating. Screen at every visit. These are pharmacological effects, not personality defects.", s: "Neurological" },
  { q: "Select ALL non-motor symptoms of Parkinson disease.", o: ["Constipation", "Anosmia (loss of smell)", "REM sleep behavior disorder", "Depression", "Improved memory"], t: "sata", ca: [0, 1, 2, 3], r: "PD non-motor symptoms: constipation, anosmia, REM sleep behavior disorder, depression, anxiety, orthostatic hypotension, cognitive decline. Many precede motor symptoms by years. Memory typically worsens, not improves.", s: "Neurological" },
  { q: "Select ALL correct statements about carbidopa-levodopa.", o: ["Gold standard treatment for PD", "Carbidopa prevents peripheral levodopa conversion", "Give on empty stomach for best absorption", "Motor fluctuations develop after 5-10 years", "Can be stopped abruptly when no longer needed"], t: "sata", ca: [0, 1, 2, 3], r: "Sinemet: gold standard, carbidopa prevents peripheral conversion (reduces nausea), give on empty stomach, and motor fluctuations develop after 5-10 years of use. NEVER stop abruptly — risk of parkinsonism-hyperpyrexia syndrome.", s: "Neurological" },
  { q: "A nurse is prioritizing four PD patients. Which should be assessed FIRST?", o: ["PD patient with mild resting tremor asking about medication timing", "PD patient who fell and hit their head, now confused and drowsy", "PD patient with end-of-dose wearing off requesting earlier medication", "PD patient scheduled for DaTscan tomorrow"], a: 1, r: "Fall with head injury, confusion, and drowsiness could indicate subdural hematoma — especially concerning because many PD patients are on anticoagulants or have falls-related risk. Requires immediate neurological assessment and imaging.", s: "Neurological" },
  { q: "Which task can be delegated to a UAP for a PD patient?", o: ["Administering carbidopa-levodopa", "Assessing for dyskinesias", "Assisting with ambulation using safety precautions", "Evaluating medication effectiveness"], a: 2, r: "UAPs can assist with safe ambulation (a critical need for PD patients with gait impairment and fall risk). Medication administration and clinical assessment require nursing licensure.", s: "Neurological" },
  { q: "What is the on-off phenomenon?", o: ["Switching medications", "Sudden unpredictable fluctuations between mobility ('on') and immobility ('off') regardless of medication timing", "A surgical procedure", "A diagnostic test"], a: 1, r: "On-off phenomenon develops after years of levodopa therapy: unpredictable switches between good motor function ('on') and severe immobility ('off'). Unlike wearing off (predictable end-of-dose deterioration), on-off is random and not related to dosing schedule.", s: "Neurological" },
  { q: "What is the DaTscan and what does it show in PD?", o: ["A blood test for dopamine", "Dopamine transporter SPECT imaging showing reduced uptake in the striatum", "An MRI protocol", "An EEG recording"], a: 1, r: "DaTscan images dopamine transporters in the striatum using radiotracer SPECT. PD shows reduced uptake reflecting presynaptic dopaminergic neuron loss. Helps differentiate PD from essential tremor and drug-induced parkinsonism (where DaTscan is normal).", s: "Neurological" },
  { q: "Cogwheel rigidity is tested by:", o: ["Asking the patient to walk", "Passively moving a limb through ROM and feeling for ratchety, jerky resistance", "Checking deep tendon reflexes", "Observing facial expressions"], a: 1, r: "The examiner passively moves the patient's arm through flexion-extension. Cogwheel rigidity = ratchet-like, jerky resistance (combining rigidity with superimposed tremor). It differs from spasticity (velocity-dependent, clasp-knife).", s: "Neurological" },
  { q: "What is micrographia?", o: ["Large handwriting", "Progressively smaller handwriting — a manifestation of bradykinesia", "Fast handwriting", "Illegible tremor-writing"], a: 1, r: "Micrographia = progressively smaller, cramped handwriting from bradykinesia. The amplitude of repetitive movements (including writing) decreases over time. Often one of the earliest noticeable motor changes in PD.", s: "Neurological" },
  { q: "What is the role of amantadine in PD treatment?", o: ["First-line dopamine replacement", "Treats levodopa-induced dyskinesias", "Replaces carbidopa", "Cures PD"], a: 1, r: "Amantadine is an NMDA receptor antagonist used primarily to treat levodopa-induced dyskinesias. It also has mild antiparkinsonian effects. It does not replace levodopa therapy.", s: "Neurological" },
  { q: "Why is exercise critically important in Parkinson disease?", o: ["It cures the disease", "Exercise is neuroprotective, improves gait/balance, reduces falls, and may slow motor progression", "Exercise is contraindicated in PD", "It only helps mood, not motor function"], a: 1, r: "Exercise has the strongest evidence for neuroprotective benefit in PD. High-intensity aerobic exercise may slow motor progression. Tai chi improves balance, boxing improves coordination, and PT provides gait training. Exercise also helps depression.", s: "Neurological" },
  { q: "What dysphagia-related complication is a leading cause of death in PD?", o: ["Malnutrition", "Aspiration pneumonia", "Bowel obstruction", "Dehydration"], a: 1, r: "Aspiration pneumonia is a leading cause of death in PD. Oropharyngeal muscles become bradykinetic, impairing swallowing. Regular swallowing assessment, SLP consultation, and dietary modifications are essential.", s: "Neurological" },
  { q: "Pramipexole carries a specific warning about:", o: ["Liver damage", "Sudden sleep attacks while driving", "Kidney failure", "Bone loss"], a: 1, r: "Dopamine agonists can cause sudden irresistible sleep attacks without prior drowsiness. Patients MUST be warned about driving and operating machinery. This is a critical patient safety counseling point.", s: "Neurological" },
  { q: "What Hoehn and Yahr stage describes bilateral disease without balance impairment?", o: ["Stage I (unilateral only)", "Stage II (bilateral without balance impairment)", "Stage III (bilateral with postural instability)", "Stage V (wheelchair/bedbound)"], a: 1, r: "Hoehn and Yahr staging: I = unilateral, II = bilateral without balance problems, III = bilateral with postural instability (independent), IV = severely disabled but can walk/stand, V = wheelchair/bedbound.", s: "Neurological" },
  { q: "What medication is available as a combination tablet (Stalevo) containing carbidopa, levodopa, AND entacapone?", o: ["Mirapex", "Stalevo (carbidopa-levodopa-entacapone)", "Azilect", "Requip"], a: 1, r: "Stalevo combines all three drugs (carbidopa + levodopa + entacapone) in one tablet, simplifying the medication regimen and improving adherence. Entacapone extends levodopa duration by blocking peripheral COMT metabolism.", s: "Neurological" },
  { q: "What is the Braak staging hypothesis?", o: ["A medication dosing guide", "Alpha-synuclein pathology begins in the gut/olfactory system, ascends to brainstem, then cortex — explaining the sequence of non-motor then motor then cognitive symptoms", "A surgical staging system", "An exercise protocol"], a: 1, r: "Braak staging proposes that alpha-synuclein pathology begins peripherally (gut, olfactory bulb), explaining early constipation and anosmia. It ascends through the brainstem (affecting sleep, autonomic function) to the substantia nigra (motor symptoms) and finally cortex (cognitive decline).", s: "Neurological" },
  { q: "A PD patient is scheduled for surgery and must be NPO. What is the critical medication consideration?", o: ["Hold all medications", "Carbidopa-levodopa must continue via NG tube — abrupt discontinuation is life-threatening", "Only give IV medications", "No special considerations"], a: 1, r: "Levodopa must be continued perioperatively to prevent parkinsonism-hyperpyrexia syndrome. If NPO, administer via NG tube (can be crushed). Coordinate medication timing with the surgical team to minimize 'off' time.", s: "Neurological" },

  // ===== DELIRIUM VS DEMENTIA (Questions 401-440) =====
  { q: "An 80-year-old who was oriented yesterday is now confused, unable to follow commands, and seeing things. Symptoms fluctuate throughout the day. What is the most likely diagnosis?", o: ["Alzheimer disease", "Delirium", "Depression", "Schizophrenia"], a: 1, r: "Acute onset, fluctuating course, inattention, and visual hallucinations = delirium. This requires immediate investigation for the underlying cause (infection, medication, metabolic, pain). Dementia develops gradually over months-years.", s: "Neurological" },
  { q: "What is the first-line management approach for delirium?", o: ["Haloperidol for all patients", "Non-pharmacological interventions: reorientation, consistent caregivers, sleep hygiene, early mobilization", "Physical restraints", "IV lorazepam"], a: 1, r: "Non-pharmacological interventions are ALWAYS first-line: frequent reorientation, consistent staff, normalize sleep-wake cycle, early mobility, ensure sensory aids, adequate hydration/nutrition, minimize unnecessary medications.", s: "Neurological" },
  { q: "Why should benzodiazepines be AVOIDED in delirium (except alcohol withdrawal)?", o: ["Too expensive", "They worsen confusion, increase sedation, and raise fall risk", "No reason to avoid them", "They cause hypertension"], a: 1, r: "Benzodiazepines worsen delirium by increasing sedation, confusion, and fall risk. They further disrupt cholinergic neurotransmission. The ONLY exception is alcohol or benzodiazepine withdrawal delirium, where benzodiazepines are the treatment.", s: "Neurological" },
  { q: "Select ALL criteria of the CAM (Confusion Assessment Method) for delirium.", o: ["Acute onset with fluctuating course", "Inattention", "Disorganized thinking", "Altered level of consciousness", "Chronic progressive memory loss"], t: "sata", ca: [0, 1, 2, 3], r: "CAM requires: (1) acute onset + fluctuating course AND (2) inattention AND EITHER (3) disorganized thinking OR (4) altered LOC. Chronic progressive memory loss is dementia, not delirium.", s: "Neurological" },
  { q: "Select ALL common causes of delirium in hospitalized elderly.", o: ["Urinary tract infection", "Medication changes (anticholinergics, benzodiazepines)", "Dehydration", "Pain", "Normal aging"], t: "sata", ca: [0, 1, 2, 3], r: "Common delirium triggers: UTI, medication changes, dehydration, pain, urinary retention, constipation, sleep deprivation, and metabolic disturbances. Delirium is NOT normal aging and always requires cause investigation.", s: "Neurological" },
  { q: "Select ALL appropriate non-pharmacological delirium prevention strategies.", o: ["Frequent reorientation with clock and calendar", "Early mobilization", "Ensure glasses and hearing aids are in place", "Normalize sleep-wake cycle", "Apply physical restraints prophylactically"], t: "sata", ca: [0, 1, 2, 3], r: "HELP (Hospital Elder Life Program) strategies: reorientation, early mobilization, sensory aids, sleep hygiene, adequate hydration. Physical restraints WORSEN delirium (increase agitation, immobility, and delirium duration).", s: "Neurological" },
  { q: "A nurse is prioritizing four elderly patients. Which should be assessed FIRST?", o: ["Dementia patient with stable baseline", "Patient who was alert this morning now acutely confused and pulling at IV lines", "Alzheimer patient eating dinner with assistance", "Dementia patient sleeping comfortably"], a: 1, r: "Acute onset confusion with behavioral change = delirium until proven otherwise. This is a medical emergency requiring immediate cause identification (infection, medication, metabolic). The underlying cause may be life-threatening.", s: "Neurological" },
  { q: "Which task can a UAP perform for a delirious patient?", o: ["Administering haloperidol", "Assessing orientation and cognition", "Sitting with the patient and providing reorientation", "Determining the cause of delirium"], a: 2, r: "UAPs can provide 1:1 supervision, reorientation, and safety monitoring. Medication administration, cognitive assessment, and diagnostic evaluation require nursing/medical judgment.", s: "Neurological" },
  { q: "What is the STRONGEST predisposing risk factor for delirium?", o: ["Hypertension", "Pre-existing dementia", "Young age", "Obesity"], a: 1, r: "Pre-existing dementia is the STRONGEST risk factor — 2-5x increased risk. Patients with dementia have reduced cognitive reserve. Delirium superimposed on dementia (DSD) has the worst outcomes and is frequently underrecognized.", s: "Neurological" },
  { q: "Which medication class most commonly CAUSES delirium in elderly patients?", o: ["Statins", "Anticholinergic medications", "ACE inhibitors", "Calcium supplements"], a: 1, r: "Anticholinergics (diphenhydramine, oxybutynin, TCAs, hydroxyzine, promethazine) reduce cholinergic neurotransmission essential for attention and arousal. Use Beers Criteria to identify and avoid inappropriate anticholinergics in elderly.", s: "Neurological" },
  { q: "Why are antipsychotics NEVER used in Lewy body dementia?", o: ["They are too expensive", "Extreme neuroleptic sensitivity causes life-threatening rigidity, obtundation, and death", "They are not effective", "No reason to avoid them"], a: 1, r: "Lewy body dementia patients have extreme sensitivity to antipsychotics (both typical and atypical). Even low doses can cause severe parkinsonism, rigidity, obtundation, NMS-like reactions, and death. ALWAYS check dementia type first.", s: "Neurological" },
  { q: "What is the difference between hypoactive and hyperactive delirium?", o: ["They are the same", "Hypoactive = withdrawn, somnolent (often MISSED); hyperactive = agitated, hallucinations (more easily recognized)", "Hypoactive is more common in children", "Hyperactive is benign"], a: 1, r: "Hypoactive delirium (withdrawn, quiet, somnolent) is more common, more often missed, and has worse prognosis than hyperactive (agitation, hallucinations, pulling at lines). Always screen for hypoactive delirium with validated tools.", s: "Neurological" },
  { q: "Donepezil (Aricept) is indicated for Alzheimer disease. What is its mechanism?", o: ["Blocks dopamine receptors", "Inhibits acetylcholinesterase, increasing acetylcholine availability in cholinergic synapses", "Blocks glutamate receptors", "Increases serotonin"], a: 1, r: "Donepezil inhibits acetylcholinesterase, preventing ACh breakdown and increasing its synaptic availability. This partially compensates for cholinergic neuron loss in Alzheimer disease. Provides modest symptomatic benefit (slows decline 6-12 months).", s: "Neurological" },
  { q: "Memantine is indicated for what stage of Alzheimer disease?", o: ["Mild only", "Moderate-to-severe", "Prevention", "All stages equally"], a: 1, r: "Memantine (NMDA receptor antagonist) is for moderate-to-severe Alzheimer disease. It blocks excessive glutamate-mediated excitotoxicity while preserving normal signaling. Can be combined with cholinesterase inhibitors.", s: "Neurological" },
  { q: "What cognitive domain is primarily impaired in delirium vs dementia?", o: ["Memory in both", "Delirium primarily impairs ATTENTION; dementia primarily impairs MEMORY", "Language in both", "Motor function in both"], a: 1, r: "Key distinction: delirium impairs attention/concentration (cannot focus, easily distractible) while memory may be secondarily affected. Dementia impairs memory (short-term first, then long-term) while attention is preserved until late stages.", s: "Neurological" },
  { q: "What is validation therapy in dementia care?", o: ["Correcting all factual errors", "Acknowledging and responding to emotions behind confused statements rather than correcting them", "Ignoring the patient", "Physical therapy"], a: 1, r: "Validation therapy acknowledges the emotional content of confused statements rather than reality-orienting corrections (which cause frustration). Helps maintain dignity and reduces agitation. Preferred over confrontation in moderate-severe dementia.", s: "Neurological" },
  { q: "How does vascular dementia differ from Alzheimer disease in its progression pattern?", o: ["Both decline smoothly", "Vascular dementia shows stepwise decline with discrete vascular events; Alzheimer shows gradual continuous decline", "Vascular dementia is always faster", "Alzheimer has sudden onset"], a: 1, r: "Vascular dementia: stepwise decline corresponding to discrete vascular events (strokes, TIAs). Alzheimer: gradual, continuous, progressive decline over months-years. History and MRI showing multi-infarct pattern help differentiate.", s: "Neurological" },
  { q: "What is the most important nursing intervention when an elderly hospitalized patient becomes acutely confused?", o: ["Apply restraints for safety", "Administer lorazepam", "Investigate the underlying cause: check vitals, UA, glucose, medication list, pain assessment", "Assume it is dementia and document"], a: 2, r: "Acute confusion in a hospitalized elder = delirium until proven otherwise. The priority is finding and treating the CAUSE: infection (UA, blood cultures), metabolic (glucose, electrolytes), medication review, pain assessment, check for urinary retention/constipation.", s: "Neurological" },
  { q: "What is delirium superimposed on dementia (DSD)?", o: ["A rare condition", "Delirium developing in a patient with pre-existing dementia — most common and dangerous combination with worst outcomes", "Same as regular dementia", "A medication side effect"], a: 1, r: "DSD is the most common and most dangerous combination. Patients with dementia are at highest risk for delirium, and DSD carries increased mortality, accelerated cognitive decline, and longer hospital stays. Frequently missed because changes are attributed to baseline dementia.", s: "Neurological" },
  { q: "Caregiver burnout in dementia care should be addressed by:", o: ["Ignoring caregiver needs", "Assessing for caregiver fatigue and depression, recommending respite care, support groups, and community resources", "Recommending immediate nursing home placement", "Only focusing on the patient"], a: 1, r: "40%+ of dementia caregivers develop depression. Nursing assessment should include caregiver burden screening, referrals to respite care, Alzheimer's Association support groups, community resources, and addressing the caregiver's own health needs.", s: "Neurological" }
];
